% --- Start of root/+flightdash/+controller/DragController.m ---
classdef DragController < handle
    % flightdash.controller.DragController
    % - SplitterDragStarted 이벤트 구독
    
    properties (Access = private)
        App
        Listeners cell = {}
    end
    
    methods
        function obj = DragController(app)
            obj.App = app;
            obj.subscribeEvents();
        end
        
        function subscribeEvents(obj)
            EB = @flightdash.util.EventBus.subscribe;
            obj.Listeners{end+1} = EB('PanelSplitterDragStarted', @(~,d) obj.onPanelSplitterStart(d));
            obj.Listeners{end+1} = EB('SplitterDragStarted', @(~,d) obj.onSplitterStart(d));
        end
        
        function onPanelSplitterStart(obj, d), obj.App.startPanelSplitterDrag(d.ChannelIdx, d.Payload); end
        function onSplitterStart(obj, d), obj.App.startHISplitterDrag(d.ChannelIdx); end
        
        % 호환 wrapper
        function startSplitter(obj, fIdx), obj.App.startHISplitterDrag(fIdx); end
        
        function delete(obj)
            for k = 1:numel(obj.Listeners)
                try, if isvalid(obj.Listeners{k}), delete(obj.Listeners{k}); end, catch, end
            end
            obj.Listeners = {};
        end
    end
end
% --- End of root/+flightdash/+controller/DragController.m ---

% --- Start of root/+flightdash/+controller/FileController.m ---
classdef FileController < handle
    % flightdash.controller.FileController
    % - 파일 로드 이벤트 구독: FlightFileRequested, AviFileRequested, CoastFileRequested
    
    properties (Access = private)
        App
        Listeners cell = {}
    end
    
    methods
        function obj = FileController(app)
            obj.App = app;
            obj.subscribeEvents();
        end
        
        function subscribeEvents(obj)
            EB = @flightdash.util.EventBus.subscribe;
            obj.Listeners{end+1} = EB('FlightFileRequested', @(~,d) obj.onFlightFile(d));
            obj.Listeners{end+1} = EB('AviFileRequested',    @(~,d) obj.onAviFile(d));
            obj.Listeners{end+1} = EB('CoastFileRequested',  @(~,~) obj.onCoastFile());
            obj.Listeners{end+1} = EB('ConfigExportRequested', @(~,~) obj.onConfigExport());
            obj.Listeners{end+1} = EB('ConfigImportRequested', @(~,~) obj.onConfigImport());
        end
        
        function onFlightFile(obj, d), obj.App.handleFlightFile(d.ChannelIdx); end
        function onAviFile(obj, d),    obj.App.loadAviFile(d.ChannelIdx); end
        function onCoastFile(obj),     obj.App.handleCoastFile(); end
        function onConfigExport(obj),  obj.App.exportConfigInteractive(); end
        function onConfigImport(obj),  obj.App.importConfigInteractive(); end
        
        % 호환 wrapper (기존 직접 호출 호환)
        function loadAvi(obj, fIdx),    obj.App.loadAviFile(fIdx); end
        function loadFlight(obj, fIdx), obj.App.handleFlightFile(fIdx); end
        
        function delete(obj)
            for k = 1:numel(obj.Listeners)
                try, if isvalid(obj.Listeners{k}), delete(obj.Listeners{k}); end, catch, end
            end
            obj.Listeners = {};
        end
    end
end
% --- End of root/+flightdash/+controller/FileController.m ---

% --- Start of root/+flightdash/+controller/PanelToggleController.m ---
classdef PanelToggleController < handle
    % flightdash.controller.PanelToggleController
    % - 패널 토글 + DebugMode + SyncToggle 이벤트 구독
    
    properties (Access = private)
        App
        Listeners cell = {}
    end
    
    methods
        function obj = PanelToggleController(app)
            obj.App = app;
            obj.subscribeEvents();
        end
        
        function subscribeEvents(obj)
            EB = @flightdash.util.EventBus.subscribe;
            obj.Listeners{end+1} = EB('PanelToggled',      @(~,d) obj.onPanelToggled(d));
            obj.Listeners{end+1} = EB('DebugModeToggled',  @(~,d) obj.onDebugToggled(d));
            obj.Listeners{end+1} = EB('SyncToggled',       @(~,~) obj.onSyncToggled());
            obj.Listeners{end+1} = EB('LayoutFitRequested', @(~,~) obj.onLayoutFitRequested());
            obj.Listeners{end+1} = EB('ChannelViewChanged', @(~,d) obj.onChannelViewChanged(d));
        end
        
        function onPanelToggled(obj, d)
            obj.App.togglePanel(d.ChannelIdx, d.Payload);
        end
        function onDebugToggled(obj, d)
            obj.App.toggleDebugMode(d.Payload);
        end
        function onSyncToggled(obj)
            obj.App.toggleSync();
        end
        function onLayoutFitRequested(obj)
            obj.App.toggleWindowMaximized();
        end
        function onChannelViewChanged(obj, d)
            obj.App.setChannelViewMode(d.Payload);
        end
        
        % 호환 wrapper
        function toggle(obj, fIdx, pnlName), obj.App.togglePanel(fIdx, pnlName); end
        
        function delete(obj)
            for k = 1:numel(obj.Listeners)
                try, if isvalid(obj.Listeners{k}), delete(obj.Listeners{k}); end, catch, end
            end
            obj.Listeners = {};
        end
    end
end
% --- End of root/+flightdash/+controller/PanelToggleController.m ---

% --- Start of root/+flightdash/+controller/PannerController.m ---
classdef PannerController < handle
    % flightdash.controller.PannerController
    % Owns compact range bar commands and handle-drag lifecycle.

    properties (Access = private)
        App
        Listeners cell = {}
        IsDragging logical = false
        DragFIdx double = 0
        DragSide char = ''
    end

    methods
        function obj = PannerController(app)
            obj.App = app;
            obj.subscribeEvents();
        end

        function subscribeEvents(obj)
            EB = @flightdash.util.EventBus.subscribe;
            obj.Listeners{end+1} = EB('PannerToggled', @(~,d) obj.togglePanner(d.ChannelIdx));
            obj.Listeners{end+1} = EB('PannerClicked', @(~,d) obj.onPannerClicked(d.ChannelIdx));
            obj.Listeners{end+1} = EB('PannerRangeChanged', @(~,d) obj.onRangeChanged(d.ChannelIdx));
            obj.Listeners{end+1} = EB('PannerResetRequested', @(~,d) obj.resetRange(d.ChannelIdx));
        end

        function togglePanner(obj, fIdx)
            app = obj.App;
            try
                if ~isfield(app.UI(fIdx), 'plotShellGrid') || ~isvalid(app.UI(fIdx).plotShellGrid), return; end
                if ~isfield(app.UI(fIdx), 'pannerPanel') || isempty(app.UI(fIdx).pannerPanel) || ~isvalid(app.UI(fIdx).pannerPanel), return; end
                curr = false;
                if isfield(app.UI(fIdx), 'PannerVisible'), curr = logical(app.UI(fIdx).PannerVisible); end
                next = ~curr;
                app.UI(fIdx).PannerVisible = next;
                app.UI(fIdx).pannerPanel.Visible = app.visibleState(next);
                rh = app.UI(fIdx).plotShellGrid.RowHeight;
                if next
                    rh{3} = flightdash.util.UIScale.px(58);
                    app.refreshPanner(fIdx);
                else
                    rh{3} = 0;
                end
                app.UI(fIdx).plotShellGrid.RowHeight = rh;
            catch ME
                app.logCaught(ME, 'Panner:toggle');
            end
        end

        function onPannerClicked(obj, fIdx)
            app = obj.App;
            try
                ax = app.UI(fIdx).pannerAxes;
                pt = ax.CurrentPoint;
                clickTime = pt(1, 1);
                timeCol = app.Models(fIdx).mappedCols.Time;
                times = app.Models(fIdx).rawData.(timeCol);
                xlims = app.currentPlotXLim(fIdx, times);
                minGap = max(eps, (times(end) - times(1)) * 0.001);
                clickTime = max(times(1), min(times(end), clickTime));
                if abs(clickTime - xlims(1)) <= abs(clickTime - xlims(2))
                    clickTime = min(clickTime, xlims(2) - minGap);
                    obj.setCurrentTabXLim(fIdx, clickTime, xlims(2));
                else
                    clickTime = max(clickTime, xlims(1) + minGap);
                    obj.setCurrentTabXLim(fIdx, xlims(1), clickTime);
                end
            catch ME
                app.logCaught(ME, 'Panner:clicked');
            end
        end

        function startHandleDrag(obj, fIdx, side, event)
            app = obj.App;
            try
                if nargin >= 4 && ~isempty(event)
                    try
                        if isprop(event, 'Button') && event.Button ~= 1
                            return;
                        end
                    catch
                    end
                end
                if isempty(app.Models(fIdx).rawData), return; end
                obj.IsDragging = true;
                obj.DragFIdx = fIdx;
                obj.DragSide = char(side);
                if isprop(app.UIFigure, 'Pointer'), app.UIFigure.Pointer = 'left-right'; end
                app.UIFigure.WindowButtonMotionFcn = @(~,~) obj.handleDragMotion();
                app.UIFigure.WindowButtonUpFcn = @(~,~) obj.stopHandleDrag();
            catch ME
                app.logCaught(ME, 'PannerHandle:start');
            end
        end

        function handleDragMotion(obj)
            app = obj.App;
            if ~obj.IsDragging, return; end
            try
                fIdx = obj.DragFIdx;
                if fIdx < 1 || fIdx > numel(app.UI), return; end
                ax = app.UI(fIdx).pannerAxes;
                if isempty(ax) || ~isvalid(ax), return; end
                pt = ax.CurrentPoint;
                newTime = pt(1, 1);
                timeCol = app.Models(fIdx).mappedCols.Time;
                times = app.Models(fIdx).rawData.(timeCol);
                xlims = app.currentPlotXLim(fIdx, times);
                minGap = max(eps, (times(end) - times(1)) * 0.001);
                newTime = max(times(1), min(times(end), newTime));
                if strcmp(obj.DragSide, 'left')
                    newTime = min(newTime, xlims(2) - minGap);
                    obj.setCurrentTabXLim(fIdx, newTime, xlims(2));
                else
                    newTime = max(newTime, xlims(1) + minGap);
                    obj.setCurrentTabXLim(fIdx, xlims(1), newTime);
                end
                drawnow limitrate nocallbacks;
            catch ME
                app.logCaught(ME, 'PannerHandle:motion');
            end
        end

        function stopHandleDrag(obj)
            app = obj.App;
            try
                obj.IsDragging = false;
                obj.DragFIdx = 0;
                obj.DragSide = '';
                if isempty(app) || ~isvalid(app), return; end
                if ~isempty(app.UIFigure) && isvalid(app.UIFigure)
                    app.UIFigure.WindowButtonMotionFcn = '';
                    app.UIFigure.WindowButtonUpFcn = '';
                    if isprop(app.UIFigure, 'Pointer'), app.UIFigure.Pointer = 'arrow'; end
                end
                drawnow limitrate;
            catch ME
                try
                    if ~isempty(app) && isvalid(app)
                        app.logCaught(ME, 'PannerHandle:stop');
                    end
                catch
                end
            end
        end

        function onRangeChanged(obj, fIdx)
            app = obj.App;
            try
                fromVal = app.UI(fIdx).pannerFrom.Value;
                toVal = app.UI(fIdx).pannerTo.Value;
                obj.setCurrentTabXLim(fIdx, fromVal, toVal);
            catch ME
                app.logCaught(ME, 'Panner:range');
            end
        end

        function resetRange(obj, fIdx)
            app = obj.App;
            try
                timeCol = app.Models(fIdx).mappedCols.Time;
                times = app.Models(fIdx).rawData.(timeCol);
                obj.setCurrentTabXLim(fIdx, times(1), times(end));
            catch ME
                app.logCaught(ME, 'Panner:reset');
            end
        end

        function setCurrentTabXLim(obj, fIdx, fromVal, toVal)
            app = obj.App;
            try
                if isempty(app.Models(fIdx).rawData), return; end
                timeCol = app.Models(fIdx).mappedCols.Time;
                times = app.Models(fIdx).rawData.(timeCol);
                if isempty(times), return; end
                fromVal = max(times(1), min(times(end), fromVal));
                toVal = max(times(1), min(times(end), toVal));
                if toVal <= fromVal
                    toVal = min(times(end), fromVal + max(eps, (times(end) - times(1)) * 0.05));
                    fromVal = max(times(1), min(fromVal, toVal - eps));
                end
                tabIdx = app.currentPlotTabIndex(fIdx);
                if ~isempty(tabIdx) && ~isempty(app.UI(fIdx).plotAxes{tabIdx})
                    app.IsProgrammaticXLim(fIdx) = true;
                    cleanup_ = onCleanup(@() obj.resetProgrammaticXLim(fIdx)); %#ok<NASGU>
                    for k = 1:numel(app.UI(fIdx).plotAxes{tabIdx})
                        ax = app.UI(fIdx).plotAxes{tabIdx}{k};
                        if ~isempty(ax) && isvalid(ax), ax.XLim = [fromVal, toVal]; end
                    end
                    clear cleanup_;
                end
                app.updatePannerViewport(fIdx);
            catch ME
                app.IsProgrammaticXLim(fIdx) = false;
                app.logCaught(ME, 'Panner:setXLim');
            end
        end

        function resetProgrammaticXLim(obj, fIdx)
            app = obj.App;
            try
                if fIdx >= 1 && fIdx <= numel(app.IsProgrammaticXLim)
                    app.IsProgrammaticXLim(fIdx) = false;
                end
            catch ME
                app.logCaught(ME, 'Panner:resetProgrammaticXLim');
            end
        end

        function delete(obj)
            obj.stopHandleDrag();
            for k = 1:numel(obj.Listeners)
                try
                    if isvalid(obj.Listeners{k}), delete(obj.Listeners{k}); end
                catch
                end
            end
            obj.Listeners = {};
        end
    end
end
% --- End of root/+flightdash/+controller/PannerController.m ---

% --- Start of root/+flightdash/+controller/PlaybackController.m ---
classdef PlaybackController < handle
    % flightdash.controller.PlaybackController
    % - 재생/이동 이벤트 구독: Slider/Nav/Spinner/Table/PlotTab 등
    
    properties (Access = private)
        App
        Listeners cell = {}
        FlightPlayTimers = {[], []}
        FlightPlayIntervalS = [1, 1]
    end
    
    methods
        function obj = PlaybackController(app)
            obj.App = app;
            obj.subscribeEvents();
        end
        
        function subscribeEvents(obj)
            EB = @flightdash.util.EventBus.subscribe;
            obj.Listeners{end+1} = EB('SliderChanging',         @(~,d) obj.onSliderChanging(d));
            obj.Listeners{end+1} = EB('SliderChanged',          @(~,d) obj.onSliderChanged(d));
            obj.Listeners{end+1} = EB('NavActionRequested',     @(~,d) obj.onNav(d));
            obj.Listeners{end+1} = EB('SpinnerChanged',         @(~,d) obj.onSpinner(d));
            obj.Listeners{end+1} = EB('TableRowSelected',       @(~,d) obj.onTableSelect(d));
            obj.Listeners{end+1} = EB('InfoFormatRequested',    @(~,d) obj.onInfoFormat(d));
            obj.Listeners{end+1} = EB('InfoOrderMoveRequested', @(~,d) obj.onInfoOrderMove(d));
            obj.Listeners{end+1} = EB('FlightPlayRequested',    @(~,d) obj.onFlightPlay(d));
            obj.Listeners{end+1} = EB('FlightStopRequested',    @(~,d) obj.onFlightStop(d));
            obj.Listeners{end+1} = EB('FlightPlayIntervalChanged', @(~,d) obj.onFlightPlayInterval(d));
        end
        
        function onSliderChanging(obj, d), obj.App.onVdubSliderChanging(d.ChannelIdx, d.Payload); end
        function onSliderChanged(obj, d),  obj.App.onVdubSliderChanged(d.ChannelIdx, d.Payload); end
        function onNav(obj, d),            obj.App.onVdubNav(d.ChannelIdx, d.Payload); end
        function onSpinner(obj, d),        obj.App.handleSpinnerChange(d.ChannelIdx, d.Payload); end
        function onTableSelect(obj, d),    obj.App.handleTableSelection(d.ChannelIdx, d.Payload); end
        function onInfoFormat(obj, d),     obj.App.setInfoFormatMode(d.ChannelIdx, d.Payload); end
        function onInfoOrderMove(obj, d),  obj.App.moveSelectedInfoRow(d.ChannelIdx, d.Payload); end
        function onFlightPlay(obj, d),     obj.startFlightPlayback(d.ChannelIdx); end
        function onFlightStop(obj, d),     obj.stopFlightPlayback(d.ChannelIdx); end
        function onFlightPlayInterval(obj, d), obj.setFlightPlayInterval(d.ChannelIdx, d.Payload); end
        
        % 호환 wrapper
        function sliderChanging(obj, fIdx, value), obj.App.onVdubSliderChanging(fIdx, value); end
        function sliderChanged(obj, fIdx, src),    obj.App.onVdubSliderChanged(fIdx, src); end
        function nav(obj, fIdx, action),           obj.App.onVdubNav(fIdx, action); end
        function spinnerChange(obj, fIdx, value),  obj.App.handleSpinnerChange(fIdx, value); end
        function tableSelect(obj, fIdx, event),    obj.App.handleTableSelection(fIdx, event); end

        function startFlightPlayback(obj, fIdx)
            try
                if fIdx < 1 || fIdx > numel(obj.App.Models), return; end
                if isempty(obj.App.Models(fIdx).rawData), return; end

                obj.stopFlightPlayback(fIdx);
                periodS = obj.resolveFlightPlayPeriod(fIdx);
                obj.FlightPlayTimers{fIdx} = timer( ...
                    'Name', sprintf('FlightDashPlay%d', fIdx), ...
                    'ExecutionMode', 'fixedSpacing', ...
                    'BusyMode', 'drop', ...
                    'Period', periodS, ...
                    'TimerFcn', @(~,~) obj.onFlightPlayTick(fIdx));
                start(obj.FlightPlayTimers{fIdx});
            catch ME
                obj.App.logCaught(ME, 'FlightPlay:start');
            end
        end

        function stopFlightPlayback(obj, fIdx)
            try
                if fIdx < 1 || fIdx > numel(obj.FlightPlayTimers), return; end
                t = obj.FlightPlayTimers{fIdx};
                if ~isempty(t)
                    try
                        if isvalid(t) && strcmpi(t.Running, 'on'), stop(t); end
                    catch
                    end
                    try
                        if isvalid(t), delete(t); end
                    catch
                    end
                end
                obj.FlightPlayTimers{fIdx} = [];
            catch ME
                obj.App.logCaught(ME, 'FlightPlay:stop');
            end
        end

        function stopAllFlightPlayback(obj)
            for fIdx = 1:numel(obj.FlightPlayTimers)
                obj.stopFlightPlayback(fIdx);
            end
        end

        function setFlightPlayInterval(obj, fIdx, value)
            try
                if fIdx < 1 || fIdx > numel(obj.FlightPlayIntervalS), return; end
                value = double(value);
                if isempty(value) || ~isfinite(value) || value <= 0
                    value = 1;
                end
                value = max(value, obj.dataSamplePeriodS(fIdx));
                obj.FlightPlayIntervalS(fIdx) = value;
                if isfield(obj.App.UI(fIdx), 'flightPlayInterval') && isvalid(obj.App.UI(fIdx).flightPlayInterval)
                    obj.App.UI(fIdx).flightPlayInterval.Value = value;
                end

                t = obj.FlightPlayTimers{fIdx};
                if ~isempty(t) && isvalid(t) && strcmpi(t.Running, 'on')
                    obj.startFlightPlayback(fIdx);
                end
            catch ME
                obj.App.logCaught(ME, 'FlightPlay:interval');
            end
        end

        function onFlightPlayTick(obj, fIdx)
            try
                if isempty(obj.App) || ~isvalid(obj.App) || fIdx < 1 || fIdx > numel(obj.App.Models)
                    obj.stopFlightPlayback(fIdx);
                    return;
                end
                if isempty(obj.App.Models(fIdx).rawData)
                    obj.stopFlightPlayback(fIdx);
                    return;
                end

                timeCol = obj.App.Models(fIdx).mappedCols.Time;
                times = obj.App.Models(fIdx).rawData.(timeCol);
                if isempty(times)
                    obj.stopFlightPlayback(fIdx);
                    return;
                end

                currIdx = max(1, min(numel(times), obj.App.Models(fIdx).currentIndex));
                nextTime = times(currIdx) + obj.resolveFlightPlayPeriod(fIdx);
                if nextTime >= times(end)
                    obj.App.applyTimeChange(fIdx, numel(times));
                    obj.stopFlightPlayback(fIdx);
                    return;
                end

                nextIdx = obj.App.findClosestIndexByTime(times, nextTime);
                if nextIdx <= currIdx && currIdx < numel(times)
                    nextIdx = currIdx + 1;
                end
                obj.App.applyTimeChange(fIdx, nextIdx);
            catch ME
                obj.App.logCaught(ME, 'FlightPlay:tick');
                try, obj.stopFlightPlayback(fIdx); catch, end
            end
        end

        function periodS = resolveFlightPlayPeriod(obj, fIdx)
            periodS = 1;
            try
                if fIdx >= 1 && fIdx <= numel(obj.FlightPlayIntervalS)
                    periodS = obj.FlightPlayIntervalS(fIdx);
                end
                periodS = max(double(periodS), obj.dataSamplePeriodS(fIdx));
                if ~isfinite(periodS) || periodS <= 0, periodS = 1; end
            catch
                periodS = 1;
            end
        end

        function dt = dataSamplePeriodS(obj, fIdx)
            dt = 0.001;
            try
                if fIdx < 1 || fIdx > numel(obj.App.Models) || isempty(obj.App.Models(fIdx).rawData), return; end
                timeCol = obj.App.Models(fIdx).mappedCols.Time;
                times = obj.App.Models(fIdx).rawData.(timeCol);
                if numel(times) < 2, return; end
                d = diff(times(1:min(numel(times), 200)));
                d = d(isfinite(d) & d > 0);
                if ~isempty(d)
                    dt = median(d);
                elseif isfield(obj.App.VideoSyncState, 'DataFps') && obj.App.VideoSyncState(fIdx).DataFps > 0
                    dt = 1 / obj.App.VideoSyncState(fIdx).DataFps;
                end
            catch
                dt = 0.001;
            end
            if ~isfinite(dt) || dt <= 0, dt = 0.001; end
        end
        
        function delete(obj)
            obj.stopAllFlightPlayback();
            for k = 1:numel(obj.Listeners)
                try, if isvalid(obj.Listeners{k}), delete(obj.Listeners{k}); end, catch, end
            end
            obj.Listeners = {};
        end
    end
end
% --- End of root/+flightdash/+controller/PlaybackController.m ---

% --- Start of root/+flightdash/+controller/PlotController.m ---
classdef PlotController < handle
    % flightdash.controller.PlotController
    % Owns Plot/Tab EventBus routing.

    properties (Access = private)
        App
        Listeners cell = {}
    end

    methods
        function obj = PlotController(app)
            obj.App = app;
            obj.subscribeEvents();
        end

        function subscribeEvents(obj)
            EB = @flightdash.util.EventBus.subscribe;
            obj.Listeners{end+1} = EB('PlotSelected',           @(~,d) obj.onPlotSelected(d));
            obj.Listeners{end+1} = EB('PlotTabAddRequested',    @(~,d) obj.onAddTab(d));
            obj.Listeners{end+1} = EB('PlotTabClearRequested',  @(~,d) obj.onClearTab(d));
            obj.Listeners{end+1} = EB('TabChanged',             @(~,d) obj.onTabChanged(d));
            obj.Listeners{end+1} = EB('PlotVisibilityChanged',  @(~,d) obj.onPlotVisibility(d));
            obj.Listeners{end+1} = EB('PlotManagerSelected',    @(~,d) obj.onPlotManagerSelected(d));
            obj.Listeners{end+1} = EB('PlotDetailChanged',      @(~,d) obj.onPlotDetailChanged(d));
            obj.Listeners{end+1} = EB('PlotAxisChanged',        @(~,d) obj.onPlotAxisChanged(d));
            obj.Listeners{end+1} = EB('PlotManagerToggled',     @(~,d) obj.onPlotManagerToggled(d));
            obj.Listeners{end+1} = EB('PlotDetailsToggled',     @(~,d) obj.onPlotDetailsToggled(d));
        end

        function onPlotSelected(obj, d),   obj.App.plotSelectedVariable(d.ChannelIdx); end
        function onAddTab(obj, d),         obj.App.addPlotTab(d.ChannelIdx); end
        function onClearTab(obj, d),       obj.App.clearCurrentTab(d.ChannelIdx); end
        function onTabChanged(obj, d),     obj.App.updateTabTimeLines(d.ChannelIdx); end
        function onPlotVisibility(obj, d), obj.App.onPlotVisibilityChanged(d.ChannelIdx, d.Payload); end
        function onPlotManagerSelected(obj, d), obj.App.onPlotManagerSelected(d.ChannelIdx, d.Payload); end
        function onPlotDetailChanged(obj, d), obj.App.onPlotDetailChanged(d.ChannelIdx, d.Payload); end
        function onPlotAxisChanged(obj, d), obj.App.onPlotAxisChanged(d.ChannelIdx, d.Payload); end
        function onPlotManagerToggled(obj, d), obj.App.togglePlotManager(d.ChannelIdx); end
        function onPlotDetailsToggled(obj, d), obj.App.togglePlotDetails(d.ChannelIdx); end

        function delete(obj)
            for k = 1:numel(obj.Listeners)
                try
                    if isvalid(obj.Listeners{k}), delete(obj.Listeners{k}); end
                catch
                end
            end
            obj.Listeners = {};
        end
    end
end
