                UIScale.px(76), UIScale.px(120), UIScale.px(120)};
            ui.HeaderGrid.RowHeight = {'fit'};
            ui.HeaderGrid.Padding = [5 5 5 5];
            ui.HeaderGrid.ColumnSpacing = 5;
