                'FontSize', 13, 'FontWeight', 'bold', ...
                'ButtonPushedFcn', @(~,~) flightdash.util.EventBus.publish( ...
                    'FlightFileRequested', flightdash.util.AppEventData(2)));
            ui.CoastButton = uibutton(ui.HeaderGrid, 'Text', 'Coast', ...
                'BackgroundColor', [0.06 0.65 0.50], 'FontColor', 'w', ...
                'FontSize', 13, 'FontWeight', 'bold', ...
                'ButtonPushedFcn', @(~,~) flightdash.util.EventBus.publish( ...
                    'CoastFileRequested', flightdash.util.AppEventData()));

            ui.ExportConfigButton = uibutton(ui.HeaderGrid, 'Text', 'Export CFG', ...
                'Tooltip', 'Export the current session configuration', ...
                'FontSize', 12, 'FontWeight', 'bold', ...
                'ButtonPushedFcn', @(~,~) flightdash.util.EventBus.publish( ...
                    'ConfigExportRequested', flightdash.util.AppEventData()));

            ui.ImportConfigButton = uibutton(ui.HeaderGrid, 'Text', 'Import CFG', ...
                'Tooltip', 'Import a saved session configuration', ...
                'FontSize', 12, 'FontWeight', 'bold', ...
                'ButtonPushedFcn', @(~,~) flightdash.util.EventBus.publish( ...
                    'ConfigImportRequested', flightdash.util.AppEventData()));

            ui.ChannelViewDropDown = uidropdown(ui.HeaderGrid, ...
                'Items', {'Both', 'Flight 1', 'Flight 2'}, ...
                'ItemsData', {'both', 'flight1', 'flight2'}, ...
                'Value', 'both', ...
                'Tooltip', 'Show both flights or focus one flight', ...
                'ValueChangedFcn', @(src,~) flightdash.util.EventBus.publish( ...
                    'ChannelViewChanged', flightdash.util.AppEventData(0, src.Value)));

