% --- Start of root/+flightdash/+util/UIScale.m ---
classdef UIScale
    % flightdash.util.UIScale
    % - High-DPI / 텍스트 스케일링 환경에서 픽셀 단위 레이아웃 보정 유틸
    % - 96 DPI를 1.0배 기준점으로 두고 현재 화면 DPI 비율로 가중
    % - 디자인 코드는 1x(96 DPI) 기준으로 작성한 뒤, 런타임에 `UIScale.px(...)`로 변환
    %
    % 사용:
    %   import flightdash.util.UIScale
    %   widths = {UIScale.px(200), UIScale.px(500), UIScale.px(250), '1x', UIScale.px(8), UIScale.px(500)};
    %
    % 캐싱:
    % - 같은 세션 내에서 DPI는 거의 변하지 않으므로 persistent로 1회 산정
    % - DPI 변경(다른 모니터로 이동 등) 시 앱 재시작 권장

    methods (Static)
        function out = px(val)
            % 디자인 픽셀(val) → 실효 픽셀(out)로 변환
            s = flightdash.util.UIScale.factor();
            out = round(val * s);
        end

        function out = pxForProfile(val, profile)
            % Layout profile별 DPI 상한을 적용한 픽셀 변환.
            s = flightdash.util.UIScale.factorForProfile(profile);
            out = round(val * s);
        end

        function out = pxForSize(val, widthPx, heightPx)
            % 현재 figure 크기로 profile을 판정한 뒤 픽셀 변환.
            if nargin < 3
                heightPx = [];
            end
            profile = flightdash.util.UIScale.profileForSize(widthPx, heightPx);
            out = flightdash.util.UIScale.pxForProfile(val, profile);
        end

        function s = factor()
            % 현재 화면 DPI 기반 스케일 비율 (96 DPI = 1.0)
            persistent cachedScale
            if isempty(cachedScale)
                cachedScale = min(flightdash.util.UIScale.rawFactor(), ...
                    flightdash.util.AppConstants.LAYOUT_SCALE_MAX_WIDE);
            end
            s = cachedScale;
        end

        function s = factorForProfile(profile)
            % Wide는 기존 DPI 보정을 유지하고, 작은 화면 profile은 폭 확대를 제한한다.
            baseScale = flightdash.util.UIScale.factor();
            profile = flightdash.util.UIScale.normalizeProfile(profile);

            switch profile
                case flightdash.util.AppConstants.LAYOUT_PROFILE_NARROW
                    maxScale = flightdash.util.AppConstants.LAYOUT_SCALE_MAX_NARROW;
                case flightdash.util.AppConstants.LAYOUT_PROFILE_COMPACT
                    maxScale = flightdash.util.AppConstants.LAYOUT_SCALE_MAX_COMPACT;
                case flightdash.util.AppConstants.LAYOUT_PROFILE_MEDIUM
                    maxScale = flightdash.util.AppConstants.LAYOUT_SCALE_MAX_MEDIUM;
                otherwise
                    maxScale = flightdash.util.AppConstants.LAYOUT_SCALE_MAX_WIDE;
            end
            s = min(baseScale, maxScale);
        end

        function profile = profileForSize(widthPx, heightPx)
            % Figure/viewport 크기를 responsive layout profile로 변환.
            if nargin < 1 || isempty(widthPx) || ~isfinite(widthPx) || widthPx <= 0
                [widthPx, fallbackH] = flightdash.util.UIScale.screenSize();
            else
                fallbackH = [];
            end

            if nargin < 2 || isempty(heightPx) || ~isfinite(heightPx) || heightPx <= 0
                if isempty(fallbackH)
                    [~, heightPx] = flightdash.util.UIScale.screenSize();
                else
                    heightPx = fallbackH;
                end
            end

            if widthPx >= flightdash.util.AppConstants.LAYOUT_WIDE_MIN_W && ...
                    heightPx >= flightdash.util.AppConstants.LAYOUT_USABLE_MIN_H
                profile = flightdash.util.AppConstants.LAYOUT_PROFILE_WIDE;
            elseif widthPx >= flightdash.util.AppConstants.LAYOUT_MEDIUM_MIN_W
                profile = flightdash.util.AppConstants.LAYOUT_PROFILE_MEDIUM;
            elseif widthPx >= flightdash.util.AppConstants.LAYOUT_COMPACT_MIN_W
                profile = flightdash.util.AppConstants.LAYOUT_PROFILE_COMPACT;
            else
                profile = flightdash.util.AppConstants.LAYOUT_PROFILE_NARROW;
            end
        end

        function profile = normalizeProfile(profile)
            if nargin < 1 || isempty(profile)
                profile = flightdash.util.AppConstants.LAYOUT_PROFILE_WIDE;
                return;
            end

            profile = lower(char(profile));
            knownProfiles = {flightdash.util.AppConstants.LAYOUT_PROFILE_WIDE, ...
                flightdash.util.AppConstants.LAYOUT_PROFILE_MEDIUM, ...
                flightdash.util.AppConstants.LAYOUT_PROFILE_COMPACT, ...
                flightdash.util.AppConstants.LAYOUT_PROFILE_NARROW};
            if ~any(strcmp(profile, knownProfiles))
                profile = flightdash.util.AppConstants.LAYOUT_PROFILE_WIDE;
            end
        end

        function s = rawFactor()
            try
                dpi = get(groot, 'ScreenPixelsPerInch');
                if isempty(dpi) || ~isfinite(dpi) || dpi <= 0
                    s = 1;
                else
                    s = dpi / 96;
                end
            catch
                s = 1;
            end
        end

        function [widthPx, heightPx] = screenSize()
            try
                scr = get(groot, 'ScreenSize');
                if numel(scr) >= 4 && all(isfinite(scr(3:4))) && scr(3) > 0 && scr(4) > 0
                    widthPx = scr(3);
                    heightPx = scr(4);
                    return;
                end
            catch
            end
            widthPx = 1920;
            heightPx = 1080;
        end
    end
end
% --- End of root/+flightdash/+util/UIScale.m ---

% --- Start of root/+flightdash/+util/EventBus.m ---
classdef EventBus < handle
    % flightdash.util.EventBus
    % - View↔Controller 결합도를 낮추는 중앙 메시지 브로커 (싱글톤)
    %
    % 사용:
    %   flightdash.util.EventBus.publish('TableRowSelected', flightdash.util.AppEventData(fIdx, evt));
    %   listener = flightdash.util.EventBus.subscribe('TableRowSelected', @(src,d) handle(d));
    %
    % 이벤트 이름 규칙: PascalCase, "동작Target" 또는 "TargetVerbed"
    
    events
        % 파일/로드
        FlightFileRequested      % FileController.loadFlight
        AviFileRequested         % FileController.loadAvi
        CoastFileRequested       % handleCoastFile
        ConfigExportRequested    % export current dashboard session config
        ConfigImportRequested    % import dashboard session config
        DebugModeToggled         % toggleDebugMode
        SyncToggled              % toggleSync (양 채널 동기 on/off)
        
        % 패널 토글 / Splitter
        LayoutFitRequested       % fit window to current monitor
        ChannelViewChanged       % both / flight1 / flight2 row visibility
        PanelToggled             % togglePanel
        PanelSplitterDragStarted % start non-video panel splitter drag
        SplitterDragStarted      % startHISplitterDrag
        
        % Playback
        SpinnerChanged           % handleSpinnerChange
        TableRowSelected         % handleTableSelection
        InfoFormatRequested      % set current info value display format
        InfoOrderMoveRequested   % move selected current info row up/down
        FlightPlayRequested      % start flight-data playback from current marker
        FlightStopRequested      % stop flight-data playback
        FlightPlayIntervalChanged % set flight-data playback interval
        PlotSelected             % plotSelectedVariable
        PlotTabAddRequested      % addPlotTab
        PlotTabClearRequested    % clearCurrentTab
        TabChanged               % updateTabTimeLines
        PlotVisibilityChanged    % togglePlotVisibility
        PlotManagerSelected      % selectManagedPlot
        PlotDetailChanged        % updatePlotDetails
        PlotAxisChanged          % set selected plot X/Y axis limits and auto modes
        DetailsToggleRequested   % toggle pooled details/plots popup figure
        PlotManagerToggled       % show/hide plot manager
        PlotDetailsToggled       % show/hide plot details
        PannerToggled            % show/hide compact range bar
        PannerClicked            % set plot window from overview click
        PannerRangeChanged       % set plot window from From/To inputs
        PannerResetRequested     % reset plot window to full time span
        RoiAddRequested          % add current ROI
        RoiSelectionChanged      % select ROI table row
        RoiDeleteSelectedRequested % delete selected ROI row
        RoiClearRequested        % clear ROI/annotation rows
        AnalysisComputeRequested % compute simple ROI statistics
        SliderChanging           % onVdubSliderChanging
        SliderChanged            % onVdubSliderChanged
        NavActionRequested       % onVdubNav
        
        % Video Sync / Hz / Cache
        VideoSyncRequested       % applyVideoSync
        HzAdjustRequested        % adjustHzValue
        HzInputChanged           % onHzInputChanged
        CacheBudgetChanged       % setCacheBudget
    end
    
    methods (Access = private)
        function obj = EventBus()
        end
    end
    
    methods (Static)
        function inst = instance()
            persistent singleton
            if isempty(singleton) || ~isvalid(singleton)
                singleton = flightdash.util.EventBus();
            end
            inst = singleton;
        end
        
        function publish(eventName, data)
            % 이벤트 발행 - data는 flightdash.util.AppEventData 권장
            if nargin < 2 || isempty(data)
                data = flightdash.util.AppEventData();
            end
            eventName = char(eventName);
            inst = flightdash.util.EventBus.instance();
            if ~flightdash.util.EventBus.isKnownEvent(eventName)
                ME = MException('flightdash:EventBus:UnknownEvent', ...
                    'Unknown EventBus event: %s', eventName);
                flightdash.util.ErrorLog.log(ME, ['EventBus:' eventName]);
                warning('flightdash:EventBus:UnknownEvent', '%s', ME.message);
                return;
            end
            try
                notify(inst, eventName, data);
            catch ME
                flightdash.util.ErrorLog.log(ME, ['EventBus:' eventName]);
                warning('flightdash:EventBus:PublishFailed', ...
                    'EventBus callback failed for "%s": %s', eventName, ME.message);
            end
        end
        
        function listener = subscribe(eventName, callback)
            % 이벤트 구독 - 호출자가 listener 핸들 보관 (GC 방지)
            eventName = char(eventName);
            if ~flightdash.util.EventBus.isKnownEvent(eventName)
                error('flightdash:EventBus:UnknownEvent', ...
                    'Unknown EventBus event: %s', eventName);
            end
            inst = flightdash.util.EventBus.instance();
            listener = addlistener(inst, eventName, callback);
        end
    end
    
    methods (Static, Access = private)
        function tf = isKnownEvent(eventName)
            mc = ?flightdash.util.EventBus;
            tf = any(strcmp(eventName, {mc.EventList.Name}));
        end
    end
end
% --- End of root/+flightdash/+util/EventBus.m ---

% --- Start of root/+flightdash/+util/AppEventData.m ---
classdef AppEventData < event.EventData
    % flightdash.util.AppEventData
    % - EventBus를 통해 전달될 데이터 페이로드 객체
    % - ChannelIdx: 채널 인덱스 (1 또는 2, 비채널 이벤트는 0)
    % - Payload: 임의 데이터 (matlab event struct, scalar, struct 등)
    
    properties
        ChannelIdx
        Payload
    end
    
    methods
        function obj = AppEventData(fIdx, payloadData)
            if nargin < 1, fIdx = 0; end
            if nargin < 2, payloadData = []; end
            obj.ChannelIdx = fIdx;
            obj.Payload = payloadData;
        end
    end
end
