% --- Start of root/+flightdash/+model/FrameCacheModel.m ---
classdef FrameCacheModel < handle
    % flightdash.model.FrameCacheModel
    % - 비행경로별 프레임 이미지 캐시 (가중 LRU + 메모리 예산)
    % - 기존 FlightDataDashboard.cacheGetFrame/cacheStoreFrame/evictByScore 통합
    % - score = (hits * recency) / bytes
    %   → 자주 + 최근에 액세스된 작은 frame 보호
    %
    % 사용 예:
    %   cm = flightdash.model.FrameCacheModel(30);   % 30 MB 예산
    %   cm.recomputeLimit(1920, 1080);               % 영상 해상도 등록
    %   cm.store(frameNo, img);
    %   img = cm.get(frameNo);                       % miss 시 [] 반환
    %   tf  = cm.has(frameNo);
    %   cm.invalidate();                              % 동기 재설정 시 호출
    %
    % 단일 채널(fIdx) 책임. 배열로 [1xN] 사용.
    
    properties (Constant, Access = private)
        MAX_CACHE_FRAMES  = 200    % 절대 상한
        MIN_CACHE_FRAMES  = 5      % 절대 하한
    end
    
    properties (Access = private)
        Cache       cell    = {}
        Keys        double  = []
        Hits        double  = []
        BytesArr    double  = []     % [PERF] frame별 바이트 (cellfun 회피)
        LastUse     uint64  = uint64([])
        BytesUsed   double  = 0
        UseCounter  uint64  = uint64(0)
        % 외부에서 clamp 보호용 (초기 0이면 보호 비활성)
        TotalFrames double  = 0
        % [PERF] 영상 해상도 기반 frame 크기 캐시 (whos 호출 회피)
        % - 같은 영상 내에서 width*height*3은 불변 → recomputeLimit 시 1회 산정
        BytesPerFrame double = 0
    end
    
    properties (Access = public)
        BudgetMB    double  = 30
        FrameLimit  double  = 50    % 동적 계산된 max frames (DynamicCacheLimit 대체)
        DebugMode   logical = false
    end
    
    methods
        function obj = FrameCacheModel(budgetMB)
            if nargin >= 1 && ~isempty(budgetMB) && budgetMB > 0
                obj.BudgetMB = budgetMB;
            end
        end
        
        function setTotalFrames(obj, total)
            % VideoModel과 동기화 — clamp 보호용
            obj.TotalFrames = max(0, round(total));
        end
        
        function img = get(obj, frameNo)
            % miss 시 [] 반환. hit 시 LRU/hits 갱신.
            img = [];
            try
                if obj.TotalFrames >= 1
                    frameNo = max(1, min(round(frameNo), obj.TotalFrames));
                end
                if isempty(obj.Keys), return; end
                foundIdx = find(obj.Keys == frameNo, 1);
                if isempty(foundIdx), return; end
                
                img = obj.Cache{foundIdx};
                
                % 사용 카운터 단조 증가 + lastUse 갱신
                obj.UseCounter = obj.UseCounter + 1;
                obj.syncLengths_();
                obj.LastUse(foundIdx) = obj.UseCounter;
                obj.Hits(foundIdx)    = obj.Hits(foundIdx) + 1;
            catch ME_silent
                flightdash.util.ErrorLog.log(ME_silent, 'cacheGet');
                img = [];
            end
        end
        
        function store(obj, frameNo, img)
            try
                obj.syncLengths_();
                obj.UseCounter = obj.UseCounter + 1;
                useNow = obj.UseCounter;
                
                foundIdx = find(obj.Keys == frameNo, 1);
                newBytes = obj.frameBytes_(img);
                if ~isempty(foundIdx)
                    % 이미 존재 → in-place 갱신
                    obj.BytesUsed = obj.BytesUsed - obj.BytesArr(foundIdx) + newBytes;
                    obj.Cache{foundIdx}    = img;
                    obj.LastUse(foundIdx)  = useNow;
                    obj.BytesArr(foundIdx) = newBytes;
                else
                    obj.Keys(end+1)     = frameNo;
                    obj.Cache{end+1}    = img;
                    obj.Hits(end+1)     = 1;
                    obj.LastUse(end+1)  = useNow;
                    obj.BytesArr(end+1) = newBytes;
                    obj.BytesUsed = obj.BytesUsed + newBytes;
                end
                
                % frame 수 한도 초과 시 가중 evict
                limit = obj.FrameLimit;
                if limit < obj.MIN_CACHE_FRAMES, limit = obj.MIN_CACHE_FRAMES; end
                if limit > obj.MAX_CACHE_FRAMES, limit = obj.MAX_CACHE_FRAMES; end
                obj.evictByScore_(limit, false);
                
                % 절대 메모리 hard limit
                hardLimitBytes = obj.BudgetMB * 1024 * 1024;
                obj.evictByScore_(hardLimitBytes, true);
            catch e
                if obj.DebugMode
                    fprintf('[Cache] store failed: %s\n', e.message);
                end
                flightdash.util.ErrorLog.log(e, 'cacheStore');
            end
        end
        
        function tf = has(obj, frameNo)
            try
                if obj.TotalFrames >= 1
                    frameNo = max(1, min(round(frameNo), obj.TotalFrames));
                end
                tf = ~isempty(find(obj.Keys == frameNo, 1));
            catch
                tf = false;
            end
        end
        
        function invalidate(obj)
            obj.Cache     = {};
            obj.Keys      = [];
            obj.Hits      = [];
            obj.LastUse   = uint64([]);
            obj.BytesArr  = [];
            obj.BytesUsed = 0;
            obj.BytesPerFrame = 0;
        end
        
        function recomputeLimit(obj, width, height)
            % 영상 해상도와 사용자 예산을 바탕으로 FrameLimit 재계산
            try
                bytesPerFrame = width * height * 3;
                if bytesPerFrame <= 0 || ~isfinite(bytesPerFrame)
                    obj.BytesPerFrame = 0;
                    obj.FrameLimit = obj.MAX_CACHE_FRAMES;
                    return;
                end
                % [PERF] frameBytes_의 whos 호출 제거를 위해 영상 해상도 기준값 캐시
                obj.BytesPerFrame = bytesPerFrame;
                budgetBytes = obj.BudgetMB * 1024 * 1024;
                maxFrames = floor(budgetBytes / bytesPerFrame);
                maxFrames = max(obj.MIN_CACHE_FRAMES, min(maxFrames, obj.MAX_CACHE_FRAMES));
                obj.FrameLimit = maxFrames;
                
                if obj.DebugMode
                    fprintf('[Cache] %dx%d, budget=%dMB, limit=%d frames\n', ...
                        width, height, obj.BudgetMB, maxFrames);
                end
                
                % 현재 캐시가 한도 초과 시 즉시 evict
                obj.syncLengths_();
                if length(obj.Keys) > maxFrames
                    obj.evictByScore_(maxFrames, false);
                end
            catch ME_silent
                flightdash.util.ErrorLog.log(ME_silent, 'cacheRecomputeLimit');
                obj.FrameLimit = 50;
            end
        end
        
        function setBudgetMB(obj, mb)
            % 예산 변경 후 호출자가 recomputeLimit를 명시적으로 부르도록 책임 분리
            if mb > 0
                obj.BudgetMB = mb;
            end
        end
        
        function s = stats(obj)
            % 디버그용 요약
            s = struct( ...
                'frameCount',  numel(obj.Keys), ...
                'frameLimit',  obj.FrameLimit, ...
                'bytesUsed',   obj.BytesUsed, ...
                'budgetBytes', obj.BudgetMB * 1024 * 1024, ...
                'useCounter',  obj.UseCounter);
        end
    end
    
    methods (Access = private)
        function syncLengths_(obj)
            % hits/lastUse/bytesArr 길이를 keys와 양방향 보정 (방어적)
            nKeys = length(obj.Keys);
            if length(obj.Hits) < nKeys
                obj.Hits(end+1:nKeys) = 1;
            elseif length(obj.Hits) > nKeys
                obj.Hits = obj.Hits(1:nKeys);
            end
            if length(obj.LastUse) < nKeys
                obj.LastUse(end+1:nKeys) = uint64(0);
            elseif length(obj.LastUse) > nKeys
                obj.LastUse = obj.LastUse(1:nKeys);
            end
            if length(obj.BytesArr) < nKeys
                % 보정 시 cell의 실제 바이트로 채움 (드물게 호출)
                for k = (length(obj.BytesArr)+1):nKeys
                    obj.BytesArr(k) = obj.frameBytes_(obj.Cache{k});
                end
            elseif length(obj.BytesArr) > nKeys
                obj.BytesArr = obj.BytesArr(1:nKeys);
            end
        end
        
        function evictByScore_(obj, limit, byBytes)
            % 가중 evict 통합 헬퍼
            % - byBytes=false: limit는 frame 개수
            % - byBytes=true : limit는 누적 바이트 (최신 1프레임만 보호)
            % - score = (hits * recency) / bytes
            % [PERF] BytesArr 사용으로 cellfun 호출 제거 (매 iteration O(N) → O(1))
            if byBytes
                minKeep = 1;   % hard byte limit: keep only the newest frame if necessary
            else
                minKeep = obj.MIN_CACHE_FRAMES;
            end
            while length(obj.Keys) > minKeep
                if byBytes
                    if obj.BytesUsed <= limit, break; end
                else
                    if length(obj.Keys) <= limit, break; end
                end
                useNow = double(obj.UseCounter);
                if useNow <= 0, useNow = 1; end
                recency = double(obj.LastUse) ./ useNow;
                recency = max(recency, 0.01);
                scores = (double(obj.Hits) .* recency) ./ max(obj.BytesArr, 1);
                
                if numel(scores) <= 1
                    break;
                end
                % 최신(가장 마지막에 추가된) 항목은 score 평가에서 제외 (보호)
                [~, evictIdx] = min(scores(1:end-1));
                obj.BytesUsed = obj.BytesUsed - obj.BytesArr(evictIdx);
                obj.Keys(evictIdx)     = [];
                obj.Cache(evictIdx)    = [];
                obj.Hits(evictIdx)     = [];
                obj.LastUse(evictIdx)  = [];
                obj.BytesArr(evictIdx) = [];
            end
        end
        
        function bytes = frameBytes_(obj, img)
            % [PERF] 같은 영상 내에서 width*height*3 불변 → 캐시값 재사용
            % - whos 호출은 심볼테이블 검색으로 비용이 크므로 핫패스에서 회피
            % - 캐시 미설정/비 uint8/해상도 변경 시에만 whos 폴백
            if obj.BytesPerFrame > 0 && isa(img, 'uint8') && numel(img) == obj.BytesPerFrame
                bytes = obj.BytesPerFrame;
            else
                info = whos('img');
                bytes = info.bytes;
            end
        end
    end
end
% --- End of root/+flightdash/+model/FrameCacheModel.m ---

% --- Start of root/+flightdash/+model/VideoModel.m ---
classdef VideoModel < handle
    % flightdash.model.VideoModel
    % - VideoReader 라이프사이클 관리 + TotalFrames 계산 + 첫 프레임 로드
    % - 디코딩 자체는 호출자가 담당(decode 결과 cache는 FrameCacheModel)
    %
    % [V3.24 events] 변경 통지:
    %   VideoLoaded   - Reader가 새로 부착되었을 때 (해상도 결정 시점)
    %   VideoCleared  - cleanup으로 Reader가 해제되었을 때
    
    events
        VideoLoaded
        VideoCleared
    end
    
    properties (Access = public)
        Reader              = []
        ImageHandle         = []
        StartTime    double = 0
        FilePath     char   = ''
        TotalFrames  double = 0
        VideoFps     double = 70
        CurrentFrame double = 1
    end
    
    methods
        function attachReader(obj, vr, filePath, imageHandle)
            % Reader 부착 + (옵션) 메타 동기 set + VideoLoaded notify
            if nargin < 2 || isempty(vr) || ~isvalid(vr)
                return;
            end
            try
                if ~isempty(obj.Reader) && isvalid(obj.Reader) && ~isequal(obj.Reader, vr)
                    delete(obj.Reader);
                end
            catch ME
                flightdash.util.ErrorLog.log(ME, 'VideoModel:replaceReader');
            end
            obj.Reader = vr;
            if nargin >= 3 && ~isempty(filePath), obj.FilePath = filePath; end
            if nargin >= 4 && ~isempty(imageHandle), obj.ImageHandle = imageHandle; end
            notify(obj, 'VideoLoaded');
        end
        
        function tf = isReady(obj)
            tf = false;
            try
                tf = ~isempty(obj.Reader) && isvalid(obj.Reader) && ...
                     ~isempty(obj.ImageHandle) && isvalid(obj.ImageHandle);
            catch
            end
        end
        
        function totalFrames = computeTotalFrames(obj, debugMode, vrOverride)
            % NumFrames 우선 → Duration*FrameRate 폴백 → 0
            % vrOverride: 호출자가 별도 VideoReader 핸들 보유 시 (호환용)
            if nargin < 2, debugMode = false; end
            totalFrames = 0;
            if nargin >= 3 && ~isempty(vrOverride)
                vr = vrOverride;
            else
                vr = obj.Reader;
            end
            if isempty(vr) || ~isvalid(vr), return; end
            try
                if isprop(vr, 'NumFrames') && ~isempty(vr.NumFrames) && vr.NumFrames > 0
                    totalFrames = double(vr.NumFrames);
                end
            catch ME
                flightdash.util.ErrorLog.log(ME, 'VideoModel:NumFrames', debugMode);
                totalFrames = 0;
            end
            estFrames = 0;
            try
                if vr.FrameRate > 0
                    estFrames = floor(vr.Duration * vr.FrameRate);
                end
            catch ME
                flightdash.util.ErrorLog.log(ME, 'VideoModel:Duration', debugMode);
            end
            if totalFrames < 1
                totalFrames = estFrames;
            elseif totalFrames <= 1 && estFrames > 1
                % 일부 codec/버전에서 NumFrames가 1로 고정되는 경우 slider range가 1에 갇힌다.
                totalFrames = estFrames;
            end
            % VFR/MP4 mismatch 경고 (디버그 시만)
            if debugMode && totalFrames > 0
                try
                    if estFrames > 0 && abs(totalFrames - estFrames) > 2
                        fprintf('[VideoModel] TotalFrames mismatch: chosen=%d, est=%d (VFR/codec metadata check)\n', ...
                            totalFrames, estFrames);
                    end
                catch
                end
            end
        end
        
        function img = loadFirstFrame(obj)
            % 첫 프레임 디코딩 + 이미지 핸들 갱신 + axes XLim/YLim/AspectRatio 보정
            % - axes는 외부에서 별도 보정 (View 책임)
            img = [];
            try
                img = read(obj.Reader, 1);
            catch
                try
                    obj.Reader.CurrentTime = 0;
                    if hasFrame(obj.Reader)
                        img = readFrame(obj.Reader);
                    end
                catch ME_silent, flightdash.util.ErrorLog.log(ME_silent, 'silent'); end
            end
            if ~isempty(img) && ~isempty(obj.ImageHandle) && isvalid(obj.ImageHandle)
                set(obj.ImageHandle, 'CData', img);
            end
        end
        
        function cleanup(obj)
            % VideoReader 명시적 해제 (파일락 즉시 반환)
            try
                if ~isempty(obj.Reader) && isvalid(obj.Reader)
                    delete(obj.Reader);
                end
            catch ME, flightdash.util.ErrorLog.log(ME, 'silent'); end
            obj.Reader       = [];
            obj.StartTime    = 0;
            obj.FilePath     = '';
            obj.TotalFrames  = 0;
            obj.CurrentFrame = 1;
            notify(obj, 'VideoCleared');
        end
    end
end
% --- End of root/+flightdash/+model/VideoModel.m ---

% --- Start of root/+flightdash/+model/SyncModel.m ---
classdef SyncModel < handle
    % flightdash.model.SyncModel
    % - 비디오/비행데이터 동기 anchor + Frame ↔ Time 변환
    % - VideoModel 의존성 없음 (TotalFrames/VideoFps만 외부에서 주입)
    %
    % [V3.23 sub-frame] AnchorOffset 도입
    % - AnchorFrame은 정수 frame (UI uispinner 입력값)
    % - AnchorOffset은 [-0.5, 0.5] 범위의 sub-frame 분수 보정
    % - 실효 anchor = AnchorFrame + AnchorOffset (분수 정밀도)
    % - 긴 영상에서 anchor 정수화로 인한 누적 오차 제거
    
    properties (Access = public)
        IsSynced     logical = false
        AnchorFrame  double  = 0     % 정수 frame
        AnchorOffset double  = 0     % [-0.5, 0.5] sub-frame 보정
        AnchorTime   double  = 0
        DataFps      double  = 50
    end
    
    methods
        function setAnchor(obj, frameNo, timeVal, offset)
            obj.AnchorFrame  = frameNo;
            obj.AnchorTime   = timeVal;
            if nargin >= 4 && ~isempty(offset)
                obj.AnchorOffset = max(-0.5, min(0.5, offset));
            else
                obj.AnchorOffset = 0;
            end
            obj.IsSynced = true;
        end
        
        function clear(obj)
            obj.IsSynced     = false;
            obj.AnchorFrame  = 0;
            obj.AnchorOffset = 0;
            obj.AnchorTime   = 0;
        end
        
        function timeVal = frameToTime(obj, frameNo, videoFps, anchorFrame, anchorTime, anchorOffset)
            if nargin < 4, anchorFrame = obj.AnchorFrame; end
            if nargin < 5, anchorTime  = obj.AnchorTime;  end
            if nargin < 6, anchorOffset = obj.AnchorOffset; end
            if videoFps <= 0
                timeVal = anchorTime; return;
            end
            % 실효 anchor = anchorFrame + anchorOffset
            timeVal = anchorTime + (frameNo - (anchorFrame + anchorOffset)) / videoFps;
        end
        
        function frameNo = timeToFrame(obj, timeVal, videoFps, totalFrames, anchorFrame, anchorTime, anchorOffset)
            if nargin < 5, anchorFrame = obj.AnchorFrame; end
            if nargin < 6, anchorTime  = obj.AnchorTime;  end
            if nargin < 7, anchorOffset = obj.AnchorOffset; end
            if isnan(anchorFrame), anchorFrame = 1; end
            if isnan(anchorOffset), anchorOffset = 0; end
            if isnan(anchorTime), anchorTime = 0; end
            if videoFps <= 0 || isnan(videoFps) || isnan(timeVal)
                frameNo = max(1, round(anchorFrame + anchorOffset)); return;
            end
            if isnan(totalFrames) || totalFrames < 1, totalFrames = 1; end
            % [JITTER GUARD] ±0.5 경계의 부동소수점 미세 오차로 ±1 frame 점프 방지
            % - timeVal이 매우 미세하게 진동할 때 round() 결과가 floor↔ceil 토글되는 현상 차단
            % - 1e-9 정밀도로 사전 절삭하여 round() 입력을 결정적으로 만듦
            rawFrame = (anchorFrame + anchorOffset) + (timeVal - anchorTime) * videoFps;
            rawFrame = round(rawFrame * 1e9) / 1e9;
            frameNo = round(rawFrame);
            if isnan(frameNo), frameNo = anchorFrame; end
            frameNo = max(1, min(frameNo, totalFrames));
        end
    end
end
% --- End of root/+flightdash/+model/SyncModel.m ---


