% --- Start of root/+flightdash/+view/PannerView.m ---
classdef PannerView < handle
    % flightdash.view.PannerView
    % Renders the compact range bar, viewport handles, and mode bands.

    properties (Access = private)
        App
    end

    methods
        function obj = PannerView(app)
            obj.App = app;
        end

        function refresh(obj, fIdx)
            app = obj.App;
            try
                if isempty(app.Models(fIdx).rawData), return; end
                if ~isfield(app.UI(fIdx), 'pannerAxes') || isempty(app.UI(fIdx).pannerAxes) || ~isvalid(app.UI(fIdx).pannerAxes)
                    return;
                end
                timeCol = app.Models(fIdx).mappedCols.Time;
                times = app.Models(fIdx).rawData.(timeCol);
                if isempty(times), return; end

                ax = app.UI(fIdx).pannerAxes;
                cla(ax);
                hold(ax, 'on');
                obj.drawModeBands(fIdx, ax, times);
                ax.YLim = [0 1];
                ax.YTick = [];
                ax.XTick = [];
                ax.XLim = [times(1) times(end)];
                grid(ax, 'off');
                obj.drawModeAxes(fIdx);
                obj.updateViewport(fIdx);
            catch ME
                app.logCaught(ME, 'Panner:refresh');
            end
        end

        function drawModeBands(obj, fIdx, ax, times)
            app = obj.App;
            try
                if ~isfield(app.UI(fIdx), 'flightModeBands') || isempty(app.UI(fIdx).flightModeBands)
                    h = patch(ax, [times(1) times(end) times(end) times(1)], [0.18 0.18 0.82 0.82], ...
                        [0.88 0.90 0.94], 'EdgeColor', [0.72 0.74 0.78], 'FaceAlpha', 1.0, 'HitTest', 'off');
                    app.excludeFromLegend(h);
                    return;
                end
                bands = app.UI(fIdx).flightModeBands;
                for k = 1:numel(bands)
                    h = patch(ax, [bands(k).Start bands(k).End bands(k).End bands(k).Start], [0.18 0.18 0.82 0.82], ...
                        bands(k).Color, 'EdgeColor', 'none', 'FaceAlpha', 0.78, 'HitTest', 'off');
                    app.excludeFromLegend(h);
                end
            catch ME
                app.logCaught(ME, 'Panner:modeBands');
            end
        end

        function updateViewport(obj, fIdx)
            app = obj.App;
            try
                if isempty(app.Models(fIdx).rawData), return; end
                if ~isfield(app.UI(fIdx), 'pannerAxes') || isempty(app.UI(fIdx).pannerAxes) || ~isvalid(app.UI(fIdx).pannerAxes)
                    return;
                end
                timeCol = app.Models(fIdx).mappedCols.Time;
                times = app.Models(fIdx).rawData.(timeCol);
                if isempty(times), return; end
                xlims = app.currentPlotXLim(fIdx, times);
                xlims(1) = max(times(1), min(times(end), xlims(1)));
                xlims(2) = max(times(1), min(times(end), xlims(2)));
                if xlims(2) <= xlims(1), xlims = [times(1), times(end)]; end

                ax = app.UI(fIdx).pannerAxes;
                hold(ax, 'on');
                if ~isfield(app.UI(fIdx), 'pannerViewPatch') || isempty(app.UI(fIdx).pannerViewPatch) || ~isvalid(app.UI(fIdx).pannerViewPatch)
                    app.UI(fIdx).pannerViewPatch = patch(ax, [xlims(1) xlims(2) xlims(2) xlims(1)], [0.08 0.08 0.92 0.92], ...
                        [0.96 0.74 0.18], 'FaceAlpha', 0.22, 'EdgeColor', [0.85 0.45 0.05], 'HitTest', 'off');
                    app.excludeFromLegend(app.UI(fIdx).pannerViewPatch);
                else
                    set(app.UI(fIdx).pannerViewPatch, 'XData', [xlims(1) xlims(2) xlims(2) xlims(1)], 'YData', [0.08 0.08 0.92 0.92]);
                end
                if ~isfield(app.UI(fIdx), 'pannerLeftHandle') || isempty(app.UI(fIdx).pannerLeftHandle) || ~isvalid(app.UI(fIdx).pannerLeftHandle)
                    app.UI(fIdx).pannerLeftHandle = xline(ax, xlims(1), 'Color', [0.85 0.45 0.05], 'LineWidth', 4.0, 'HitTest', 'on');
                    app.UI(fIdx).pannerLeftHandle.ButtonDownFcn = @(~,event) app.startPannerHandleDrag(fIdx, 'left', event);
                    app.excludeFromLegend(app.UI(fIdx).pannerLeftHandle);
                else
                    app.UI(fIdx).pannerLeftHandle.Value = xlims(1);
                end
                if ~isfield(app.UI(fIdx), 'pannerRightHandle') || isempty(app.UI(fIdx).pannerRightHandle) || ~isvalid(app.UI(fIdx).pannerRightHandle)
                    app.UI(fIdx).pannerRightHandle = xline(ax, xlims(2), 'Color', [0.85 0.45 0.05], 'LineWidth', 4.0, 'HitTest', 'on');
                    app.UI(fIdx).pannerRightHandle.ButtonDownFcn = @(~,event) app.startPannerHandleDrag(fIdx, 'right', event);
                    app.excludeFromLegend(app.UI(fIdx).pannerRightHandle);
                else
                    app.UI(fIdx).pannerRightHandle.Value = xlims(2);
                end
                currIdx = max(1, min(numel(times), app.Models(fIdx).currentIndex));
                currTime = times(currIdx);
                if ~isfield(app.UI(fIdx), 'pannerCurrentLine') || isempty(app.UI(fIdx).pannerCurrentLine) || ~isvalid(app.UI(fIdx).pannerCurrentLine)
                    app.UI(fIdx).pannerCurrentLine = xline(ax, currTime, 'r', 'LineWidth', 1.5, 'HitTest', 'off');
                    app.excludeFromLegend(app.UI(fIdx).pannerCurrentLine);
                else
                    app.UI(fIdx).pannerCurrentLine.Value = currTime;
                end
                try, uistack(app.UI(fIdx).pannerViewPatch, 'bottom'); catch, end
                if isfield(app.UI(fIdx), 'pannerFrom') && isvalid(app.UI(fIdx).pannerFrom), app.UI(fIdx).pannerFrom.Value = xlims(1); end
                if isfield(app.UI(fIdx), 'pannerTo') && isvalid(app.UI(fIdx).pannerTo), app.UI(fIdx).pannerTo.Value = xlims(2); end
            catch ME
                app.logCaught(ME, 'Panner:viewport');
            end
        end

        function drawModeAxes(obj, fIdx)
            app = obj.App;
            try
                if ~isfield(app.UI(fIdx), 'modeAxes') || isempty(app.UI(fIdx).modeAxes) || ~isvalid(app.UI(fIdx).modeAxes)
                    return;
                end
                ax = app.UI(fIdx).modeAxes;
                cla(ax);
                hold(ax, 'on');
                if isempty(app.Models(fIdx).rawData), return; end
                timeCol = app.Models(fIdx).mappedCols.Time;
                times = app.Models(fIdx).rawData.(timeCol);
                ax.XLim = [times(1), times(end)];
                ax.YLim = [0 1];
                ax.XTick = [];
                ax.YTick = [];
                if ~isfield(app.UI(fIdx), 'flightModeBands'), return; end
                bands = app.UI(fIdx).flightModeBands;
                for k = 1:numel(bands)
                    h = patch(ax, [bands(k).Start bands(k).End bands(k).End bands(k).Start], [0 0 1 1], ...
                        bands(k).Color, 'EdgeColor', 'none', 'FaceAlpha', 0.95, 'HitTest', 'off');
                    app.excludeFromLegend(h);
                end
            catch ME
                app.logCaught(ME, 'FlightModes:draw');
            end
        end
    end
end
% --- End of root/+flightdash/+view/PannerView.m ---

% --- Start of root/+flightdash/+view/PlotView.m ---
classdef PlotView < handle
    % flightdash.view.PlotView
    % Runtime plot/tab rendering facade for one dashboard channel.

    properties (Access = private)
        App
        FIdx double = 1
    end

    methods
        function obj = PlotView(app, fIdx)
            obj.App = app;
            obj.FIdx = fIdx;
        end

        function addTab(obj)
            app = obj.App;
            fIdx = obj.FIdx;
            nTabs = length(app.UI(fIdx).plotTabs);
            if nTabs >= flightdash.util.AppConstants.MAX_TABS
                errordlg(sprintf('Maximum %d plot tabs can be created.', flightdash.util.AppConstants.MAX_TABS), 'Plot Tabs');
                return;
            end

            newTab = uitab(app.UI(fIdx).tabGroup, 'Title', sprintf('Tab %d', nTabs + 1));
            app.UI(fIdx).plotTabs(end + 1) = newTab;

            plotLayout = uigridlayout(newTab, 'ColumnWidth', {'1x'}, 'RowHeight', {}, ...
                                      'Padding', [5 5 5 5], 'RowSpacing', 5, 'Scrollable', 'on');
            app.UI(fIdx).plotLayouts{end + 1} = plotLayout;

            tabIdx = nTabs + 1;
            app.UI(fIdx).plotAxes{tabIdx} = {};
            app.UI(fIdx).timeLines{tabIdx} = {};
            app.UI(fIdx).timeMarkers{tabIdx} = {};
            app.UI(fIdx).plotValueLabels{tabIdx} = {};
            app.UI(fIdx).plotData{tabIdx} = {};
            app.UI(fIdx).plotMeta{tabIdx} = {};
            app.UI(fIdx).xLimListeners{tabIdx} = {};

            app.UI(fIdx).tabGroup.SelectedTab = newTab;
            app.UI(fIdx).selectedPlotIdx = 0;
            obj.refreshCompanions();
        end

        function clearCurrentTab(obj)
            app = obj.App;
            fIdx = obj.FIdx;
            currTab = app.UI(fIdx).tabGroup.SelectedTab;
            if isempty(currTab), return; end
            tabIdx = find(app.UI(fIdx).plotTabs == currTab, 1);
            if isempty(tabIdx), return; end

            app.deleteListeners(app.UI(fIdx).xLimListeners{tabIdx});
            app.deleteGraphicsHandles(app.UI(fIdx).timeLines{tabIdx});
            app.deleteGraphicsHandles(app.UI(fIdx).timeMarkers{tabIdx});
            app.deleteGraphicsHandles(app.UI(fIdx).plotAxes{tabIdx});

            targetLayout = app.UI(fIdx).plotLayouts{tabIdx};
            try
                if ~isempty(targetLayout) && isvalid(targetLayout)
                    delete(targetLayout.Children);
                    targetLayout.RowHeight = {};
                end
            catch ME
                app.logCaught(ME, 'PlotView:clearCurrentTab');
            end

            app.UI(fIdx).plotAxes{tabIdx} = {};
            app.UI(fIdx).timeLines{tabIdx} = {};
            app.UI(fIdx).timeMarkers{tabIdx} = {};
            app.UI(fIdx).plotValueLabels{tabIdx} = {};
            app.UI(fIdx).plotData{tabIdx} = {};
            app.UI(fIdx).plotMeta{tabIdx} = {};
            app.UI(fIdx).xLimListeners{tabIdx} = {};
            app.UI(fIdx).selectedPlotIdx = 0;
            obj.refreshCompanions();
        end

        function clearAllTabs(obj)
            app = obj.App;
            fIdx = obj.FIdx;
            for i = 1:length(app.UI(fIdx).plotTabs)
                if i <= length(app.UI(fIdx).xLimListeners)
                    app.deleteListeners(app.UI(fIdx).xLimListeners{i});
                end
                try
                    if ~isempty(app.UI(fIdx).plotTabs(i)) && isvalid(app.UI(fIdx).plotTabs(i))
                        delete(app.UI(fIdx).plotTabs(i));
                    end
                catch ME
                    app.logCaught(ME, 'PlotView:clearAllTabs');
                end
            end

            app.UI(fIdx).plotTabs = [];
            app.UI(fIdx).plotLayouts = {};
            app.UI(fIdx).plotAxes = cell(1, flightdash.util.AppConstants.MAX_TABS);
            app.UI(fIdx).timeLines = cell(1, flightdash.util.AppConstants.MAX_TABS);
            app.UI(fIdx).timeMarkers = cell(1, flightdash.util.AppConstants.MAX_TABS);
            app.UI(fIdx).plotValueLabels = cell(1, flightdash.util.AppConstants.MAX_TABS);
            app.UI(fIdx).plotData = cell(1, flightdash.util.AppConstants.MAX_TABS);
            app.UI(fIdx).plotMeta = cell(1, flightdash.util.AppConstants.MAX_TABS);
            app.UI(fIdx).xLimListeners = cell(1, flightdash.util.AppConstants.MAX_TABS);
            app.UI(fIdx).selectedPlotIdx = 0;

            obj.addTab();
            app.drawRoiBands(fIdx);
        end

        function addSelectedVariable(obj)
            app = obj.App;
            fIdx = obj.FIdx;
            selRow = app.Models(fIdx).selectedRow;
            if isempty(selRow) || selRow < 1, return; end
            if isempty(app.Models(fIdx).rawData), return; end

            currTab = app.UI(fIdx).tabGroup.SelectedTab;
            if isempty(currTab)
                obj.addTab();
                currTab = app.UI(fIdx).tabGroup.SelectedTab;
            end

            tabIdx = find(app.UI(fIdx).plotTabs == currTab, 1);
            if isempty(tabIdx)
                errordlg('Current plot tab is not valid. Add a tab first.', 'Plot Error');
                return;
            end

            numPlots = length(app.UI(fIdx).plotAxes{tabIdx});
            if numPlots >= flightdash.util.AppConstants.MAX_PLOTS_PER_TAB
                errordlg(sprintf('Maximum %d plots can be added to one tab.', flightdash.util.AppConstants.MAX_PLOTS_PER_TAB), 'Plot Limit');
                return;
            end

            if selRow > length(app.Models(fIdx).displayMeta)
                errordlg('Selected row is not valid.', 'Selection Error');
                return;
            end

            meta = app.Models(fIdx).displayMeta(selRow);
            yCol = meta.header;
            yLabelStr = sprintf('%s (%s)', meta.header, meta.unit);
            timeCol = app.Models(fIdx).mappedCols.Time;

            if ~ismember(yCol, app.Models(fIdx).rawData.Properties.VariableNames)
                errordlg(sprintf('Column "%s" was not found.', yCol), 'Data Error');
                return;
            end

            tData = app.Models(fIdx).rawData.(timeCol);
            yData = app.Models(fIdx).rawData.(yCol);
            targetLayout = app.UI(fIdx).plotLayouts{tabIdx};
            targetLayout.RowHeight{end + 1} = flightdash.util.AppConstants.PLOT_ROW_HEIGHT;
            newRowIdx = numel(targetLayout.RowHeight);
            app.updatePlotRowHeights(fIdx);

            p = uipanel(targetLayout, 'BorderType', 'line', 'BackgroundColor', 'w');
            p.Layout.Row = newRowIdx;
            p.Layout.Column = 1;

            axGrid = uigridlayout(p, 'ColumnWidth', {'1x'}, 'RowHeight', {'1x'}, 'Padding', [5 5 5 5]);
            ax = uiaxes(axGrid);
            ax.Layout.Row = 1;
            ax.Layout.Column = 1;
            ax.Interactions = [panInteraction, zoomInteraction];
            tb = axtoolbar(ax, {'restoreview', 'zoomin', 'zoomout', 'pan'});
            tb.Visible = 'on';

            grid(ax, 'on');
            set(ax, 'XMinorGrid', 'on', 'YMinorGrid', 'on');
            mainLine = plot(ax, tData, yData, 'LineWidth', 1.5, ...
                'Color', [0.15 0.38 0.82], 'DisplayName', meta.header, 'HitTest', 'off');
            title(ax, meta.header, 'Interpreter', 'none', 'FontWeight', 'bold');
            xlabel(ax, 'Time(s)', 'FontWeight', 'bold', 'FontSize', 9);
            ylabel(ax, yLabelStr, 'FontWeight', 'bold', 'FontSize', 10, 'Interpreter', 'none');

            hold(ax, 'on');
            currIdx = app.Models(fIdx).currentIndex;
            currTime = tData(currIdx);
            currY = yData(currIdx);
            tl = xline(ax, currTime, 'r', 'LineWidth', 3.0, 'Alpha', 0.5, 'HitTest', 'on');
            mk = plot(ax, currTime, currY, 'p', 'MarkerFaceColor', [0.98 0.75 0.14], ...
                      'MarkerEdgeColor', [0.71 0.33 0.04], 'MarkerSize', 14, 'HitTest', 'on');
            valueLabel = text(ax, currTime, currY, app.plotValueLabelText(meta.header, currY, meta.format), ...
                'Interpreter', 'none', 'FontSize', 10, 'FontWeight', 'bold', ...
                'Color', [0.12 0.12 0.12], 'BackgroundColor', [1 1 1], ...
                'Margin', 3, 'VerticalAlignment', 'bottom', 'HorizontalAlignment', 'left', ...
                'HitTest', 'off');
            app.excludeFromLegend(tl);
            app.excludeFromLegend(mk);
            app.excludeFromLegend(valueLabel);

            tl.ButtonDownFcn = @(src, event) app.startPlotMarkerDrag(fIdx, tabIdx, src, event);
            mk.ButtonDownFcn = @(src, event) app.startPlotMarkerDrag(fIdx, tabIdx, src, event);

            app.UI(fIdx).plotAxes{tabIdx}{end + 1} = ax;
            app.UI(fIdx).timeLines{tabIdx}{end + 1} = tl;
            app.UI(fIdx).timeMarkers{tabIdx}{end + 1} = mk;
            app.UI(fIdx).plotValueLabels{tabIdx}{end + 1} = valueLabel;
            app.UI(fIdx).plotData{tabIdx}{end + 1} = yData;
            plotInfo = struct('Name', meta.header, 'YColumn', yCol, 'YLabel', yLabelStr, ...
                'Unit', meta.unit, 'Format', meta.format, 'MainLine', mainLine, ...
                'Panel', p, 'Visible', true, 'Legend', false, ...
                'XLimMode', 'auto', 'YLimMode', 'auto', 'XLim', ax.XLim, 'YLim', ax.YLim);
            app.UI(fIdx).plotMeta{tabIdx}{end + 1} = plotInfo;

            L = addlistener(ax, 'XLim', 'PostSet', @(~,~) app.handlePlotXLimChange(fIdx, ax));
            app.UI(fIdx).xLimListeners{tabIdx}{end + 1} = L;

            allAxes = [app.UI(fIdx).plotAxes{tabIdx}{:}];
            if numel(allAxes) > 1
                linkaxes(allAxes, 'x');
            end
            app.UI(fIdx).selectedPlotIdx = numel(app.UI(fIdx).plotAxes{tabIdx});
            obj.refreshCompanions();
            app.updateFlightModeBands(fIdx);
            drawnow;
        end

        function updateTimeIndicators(obj, currIdx, currTime)
            app = obj.App;
            fIdx = obj.FIdx;
            currTab = app.UI(fIdx).tabGroup.SelectedTab;
            if isempty(currTab), return; end

            tabIdx = find(app.UI(fIdx).plotTabs == currTab, 1);
            if isempty(tabIdx), return; end

            if ~isempty(app.UI(fIdx).plotAxes{tabIdx}) && app.currentTabXAutoEnabled(fIdx, tabIdx)
                firstAx = app.UI(fIdx).plotAxes{tabIdx}{1};
                try
                    if isvalid(firstAx)
                        xlims = firstAx.XLim;
                        xMin = xlims(1);
                        xMax = xlims(2);
                        xWidth = xMax - xMin;
                        newLims = [];
                        if currTime > xMax
                            newMin = xMax;
                            newMax = xMax + xWidth;
                            while currTime > newMax
                                newMin = newMax;
                                newMax = newMax + xWidth;
                            end
                            newLims = [newMin, newMax];
                        elseif currTime < xMin
                            newMax = xMin;
                            newMin = xMin - xWidth;
                            while currTime < newMin
                                newMax = newMin;
                                newMin = newMin - xWidth;
                            end
                            newLims = [newMin, newMax];
                        end
                        if ~isempty(newLims)
                            app.setPlotProgrammaticXLim(fIdx, true);
                            firstAx.XLim = newLims;
                            app.setPlotProgrammaticXLim(fIdx, false);
                        end
                    end
                catch ME
                    app.setPlotProgrammaticXLim(fIdx, false);
                    app.logCaught(ME, 'PlotView:autoPage');
                end
            end

            tlArr = app.UI(fIdx).timeLines{tabIdx};
            mkArr = app.UI(fIdx).timeMarkers{tabIdx};
            labelArr = {};
            if isfield(app.UI(fIdx), 'plotValueLabels') && tabIdx <= numel(app.UI(fIdx).plotValueLabels)
                labelArr = app.UI(fIdx).plotValueLabels{tabIdx};
            end
            dataArr = app.UI(fIdx).plotData{tabIdx};
            metaArr = app.UI(fIdx).plotMeta{tabIdx};

            for i = 1:length(tlArr)
                try
                    if ~isempty(tlArr{i}) && isvalid(tlArr{i})
                        set(tlArr{i}, 'Value', currTime);
                    end
                    if ~isempty(mkArr{i}) && isvalid(mkArr{i})
                        yData = dataArr{i};
                        if currIdx >= 1 && currIdx <= numel(yData)
                            set(mkArr{i}, 'XData', currTime, 'YData', yData(currIdx));
                            if i <= numel(labelArr) && ~isempty(labelArr{i}) && isvalid(labelArr{i})
                                labelText = app.plotValueLabelText(metaArr{i}.YColumn, yData(currIdx), metaArr{i}.Format);
                                set(labelArr{i}, 'Position', [currTime yData(currIdx) 0], 'String', labelText);
                            end
                        end
                    end
                catch ME
                    app.logCaught(ME, 'PlotView:updateIndicators');
                end
            end
            app.updatePannerViewport(fIdx);
            app.refreshStatsFigure(fIdx);
        end
    end

    methods (Access = private)
        function refreshCompanions(obj)
            app = obj.App;
            fIdx = obj.FIdx;
            app.refreshPlotManager(fIdx);
            app.refreshPlotDetails(fIdx);
            app.refreshPanner(fIdx);
        end
    end
end
% --- End of root/+flightdash/+view/PlotView.m ---

% --- Start of root/+flightdash/+view/ResponsiveLayoutManager.m ---
classdef ResponsiveLayoutManager < handle
    % flightdash.view.ResponsiveLayoutManager
    % Owns figure sizing, responsive grid profiles, panel rails, and summaries.

    methods
        function applyLayout(obj, app, reason) %#ok<INUSD>
            if nargin < 3, reason = ''; end %#ok<NASGU>
            if app.InResponsiveLayout, return; end
            if isempty(app.UIFigure) || ~isvalid(app.UIFigure), return; end

            app.InResponsiveLayout = true;
            cleanup_ = onCleanup(@() obj.finishResponsiveLayout(app)); %#ok<NASGU>
            try
                [figW, figH] = obj.currentFigureSizePx(app);
                profile = flightdash.util.UIScale.profileForSize(figW, figH);
                app.LayoutProfile = profile;
                app.LastLayoutSize = [figW, figH];
                obj.applyResponsiveShellLayout(app, profile, figH);

                if isempty(app.UI), return; end
                nChannels = min(2, numel(app.UI));
                for fIdx = 1:nChannels
                    obj.applyResponsiveChannelLayout(app, fIdx, profile);
                    try, app.updatePlotRowHeights(fIdx); catch, end
                end
            catch ME
                app.logCaught(ME, 'Layout:responsive');
            end
        end

        function finishResponsiveLayout(~, app)
            app.InResponsiveLayout = false;
        end

        function pos = initialFigurePosition(obj, app)
            mon = obj.primaryMonitorRect();
            pos = obj.figurePositionForMonitor(mon, false);
        end

        function pos = fitFigurePosition(obj, app)
            mon = obj.currentMonitorRect(app);
            pos = obj.figurePositionForMonitor(mon, true);
        end

        function [figW, figH] = currentFigureSizePx(~, app)
            figW = NaN;
            figH = NaN;
            try
                pos = getpixelposition(app.UIFigure);
                if numel(pos) >= 4 && all(isfinite(pos(3:4))) && pos(3) > 0 && pos(4) > 0
                    figW = pos(3);
                    figH = pos(4);
                    return;
                end
            catch
            end

            try
                oldUnits = app.UIFigure.Units;
                app.UIFigure.Units = 'pixels';
                pos = app.UIFigure.Position;
                app.UIFigure.Units = oldUnits;
                if numel(pos) >= 4 && all(isfinite(pos(3:4))) && pos(3) > 0 && pos(4) > 0
                    figW = pos(3);
                    figH = pos(4);
                    return;
                end
            catch
            end

            [figW, figH] = flightdash.util.UIScale.screenSize();
        end

        function mon = primaryMonitorRect(~)
            try
                monitors = get(groot, 'MonitorPositions');
                if ~isempty(monitors) && size(monitors, 2) >= 4
                    mon = monitors(1, 1:4);
                    return;
                end
            catch
            end
            [screenW, screenH] = flightdash.util.UIScale.screenSize();
            mon = [1, 1, screenW, screenH];
        end

        function mon = currentMonitorRect(obj, app)
            try
                monitors = get(groot, 'MonitorPositions');
                if isempty(monitors) || size(monitors, 2) < 4
                    mon = obj.primaryMonitorRect();
                    return;
                end

                oldUnits = app.UIFigure.Units;
                app.UIFigure.Units = 'pixels';
                figPos = app.UIFigure.Position;
                app.UIFigure.Units = oldUnits;
                figCenter = [figPos(1) + figPos(3)/2, figPos(2) + figPos(4)/2];

                for k = 1:size(monitors, 1)
                    r = monitors(k, 1:4);
                    if figCenter(1) >= r(1) && figCenter(1) <= r(1) + r(3) && ...
                            figCenter(2) >= r(2) && figCenter(2) <= r(2) + r(4)
                        mon = r;
                        return;
                    end
                end

                centers = [monitors(:,1) + monitors(:,3)/2, monitors(:,2) + monitors(:,4)/2];
                dist2 = (centers(:,1) - figCenter(1)).^2 + (centers(:,2) - figCenter(2)).^2;
                [~, idx] = min(dist2);
                mon = monitors(idx, 1:4);
            catch
                mon = obj.primaryMonitorRect();
            end
        end

        function pos = figurePositionForMonitor(~, mon, fitToScreen)
            marginX = min(flightdash.util.AppConstants.FIGURE_MARGIN_X, max(8, floor(mon(3) * 0.04)));
            marginY = min(flightdash.util.AppConstants.FIGURE_MARGIN_Y, max(16, floor(mon(4) * 0.08)));
            availW = max(360, mon(3) - 2 * marginX);
            availH = max(360, mon(4) - 2 * marginY);

            if fitToScreen
                w = availW;
                h = availH;
            else
                w = min(flightdash.util.AppConstants.FIGURE_INITIAL_W, availW);
                h = min(flightdash.util.AppConstants.FIGURE_INITIAL_H, availH);
                if availW >= flightdash.util.AppConstants.FIGURE_MIN_W
                    w = max(w, flightdash.util.AppConstants.FIGURE_MIN_W);
                end
                if availH >= flightdash.util.AppConstants.FIGURE_MIN_H
                    h = max(h, flightdash.util.AppConstants.FIGURE_MIN_H);
                end
            end

            x = mon(1) + max(4, floor((mon(3) - w) / 2));
            y = mon(2) + max(24, floor((mon(4) - h) / 2));
            pos = [x, y, max(360, round(w)), max(360, round(h))];
        end

        function applyResponsiveShellLayout(obj, app, profile, figH)
            try
                obj.applyResponsiveHeaderLayout(app, profile);
            catch ME
                app.logCaught(ME, 'Layout:header');
            end
            try
                obj.applyResponsiveBodyLayout(app, profile, figH);
            catch ME
                app.logCaught(ME, 'Layout:body');
            end
        end

        function applyResponsiveHeaderLayout(obj, app, profile)
            if ~isfield(app.LayoutHandles, 'header'), return; end
            h = app.LayoutHandles.header;
            if ~isfield(h, 'HeaderGrid') || isempty(h.HeaderGrid) || ~isvalid(h.HeaderGrid), return; end

            profile = flightdash.util.UIScale.normalizeProfile(profile);
            UIScale = flightdash.util.UIScale;
            isNarrow = strcmp(profile, flightdash.util.AppConstants.LAYOUT_PROFILE_NARROW);
            isCompact = strcmp(profile, flightdash.util.AppConstants.LAYOUT_PROFILE_COMPACT);

            g = h.HeaderGrid;
            if isNarrow
                g.RowHeight = {UIScale.pxForProfile(32, profile), UIScale.pxForProfile(32, profile), UIScale.pxForProfile(32, profile)};
                obj.placeGridItem(h.Flight1Button, 1, 1);
                obj.placeGridItem(h.Flight2Button, 1, 2);
                obj.placeGridItem(h.CoastButton, 1, 3);
                obj.placeGridItem(h.FitScreenButton, 1, 4);
                obj.placeGridItem(h.ExportConfigButton, 2, 1);
                obj.placeGridItem(h.ImportConfigButton, 2, 2);
                obj.placeGridItem(h.ChannelViewDropDown, 2, 3);
                obj.placeGridItem(h.DebugBox, 2, 4);
                obj.placeGridItem(h.SyncInput, 3, [1 2]);
                obj.placeGridItem(h.SyncBtn, 3, [3 4]);
                obj.setHandleVisible(h.HeaderSpacer, false);

                g.ColumnWidth = {'1x', '1x', '1x', UIScale.pxForProfile(42, profile)};
                g.Padding = [3 3 3 3];
                g.ColumnSpacing = 3;
                g.RowSpacing = 3;
            else
                if isCompact
                    fileW = 96; coastW = 80; cfgW = 92; viewW = 88; fitW = 38; debugW = 70; inputW = 120; syncW = 120;
                else
                    fileW = 104; coastW = 88; cfgW = 100; viewW = 92; fitW = 42; debugW = 80; inputW = 145; syncW = 145;
                end

                g.ColumnWidth = { ...
                    UIScale.pxForProfile(fileW, profile), ...
                    UIScale.pxForProfile(coastW, profile), ...
                    UIScale.pxForProfile(cfgW, profile), ...
                    UIScale.pxForProfile(viewW, profile), ...
                    '1x', ...
                    UIScale.pxForProfile(fitW, profile), ...
                    UIScale.pxForProfile(debugW, profile), ...
                    UIScale.pxForProfile(inputW, profile), ...
                    UIScale.pxForProfile(syncW, profile)};
                g.Padding = [5 5 5 5];
                g.ColumnSpacing = 5;
                g.RowSpacing = 3;

                obj.placeGridItem(h.Flight1Button, 1, 1);
                obj.placeGridItem(h.Flight2Button, 1, 2);
                obj.placeGridItem(h.CoastButton, 1, 3);
                obj.placeGridItem(h.ExportConfigButton, 1, 4);
                obj.placeGridItem(h.ImportConfigButton, 1, 5);
                obj.placeGridItem(h.ChannelViewDropDown, 1, 6);
                obj.placeGridItem(h.HeaderSpacer, 1, 7);
                obj.placeGridItem(h.FitScreenButton, 1, 8);
                obj.placeGridItem(h.DebugBox, 1, 9);
                obj.placeGridItem(h.SyncInput, 1, 10);
                obj.placeGridItem(h.SyncBtn, 1, 11);
                obj.setHandleVisible(h.HeaderSpacer, true);
                g.RowHeight = {'fit'};
            end
            app.updateMaximizeButtonState();
        end

        function applyResponsiveBodyLayout(obj, app, profile, figH)
            if ~isfield(app.LayoutHandles, 'bodyGrid'), return; end
            bodyGrid = app.LayoutHandles.bodyGrid;
            if isempty(bodyGrid) || ~isvalid(bodyGrid), return; end

            profile = flightdash.util.UIScale.normalizeProfile(profile);
            switch lower(char(app.ChannelViewMode))
                case 'flight1'
                    bodyGrid.RowHeight = {'1x', 0};
                    obj.setChannelRootVisible(app, 1, true);
                    obj.setChannelRootVisible(app, 2, false);
                    try, bodyGrid.Scrollable = 'on'; catch, end
                    return;
                case 'flight2'
                    bodyGrid.RowHeight = {0, '1x'};
                    obj.setChannelRootVisible(app, 1, false);
                    obj.setChannelRootVisible(app, 2, true);
                    try, bodyGrid.Scrollable = 'on'; catch, end
                    return;
                otherwise
                    obj.setChannelRootVisible(app, 1, true);
                    obj.setChannelRootVisible(app, 2, true);
            end
            isShort = ~isfinite(figH) || figH < flightdash.util.AppConstants.LAYOUT_SHORT_VIEW_H || ...
                strcmp(profile, flightdash.util.AppConstants.LAYOUT_PROFILE_NARROW);
            if isShort
                rowH = flightdash.util.UIScale.pxForProfile(obj.channelMinHeightForProfile(profile), profile);
                bodyGrid.RowHeight = {rowH, rowH};
            else
                bodyGrid.RowHeight = {'1x', '1x'};
            end
            try, bodyGrid.Scrollable = 'on'; catch, end
        end

        function setChannelRootVisible(obj, app, fIdx, tf)
            try
                if fIdx <= numel(app.UI) && isfield(app.UI(fIdx), 'rootPanel') && ...
                        ~isempty(app.UI(fIdx).rootPanel) && isvalid(app.UI(fIdx).rootPanel)
                    app.UI(fIdx).rootPanel.Visible = obj.visibleState(tf);
                elseif fIdx <= numel(app.UI) && isfield(app.UI(fIdx), 'channelPanel') && ...
                        ~isempty(app.UI(fIdx).channelPanel) && isvalid(app.UI(fIdx).channelPanel)
                    app.UI(fIdx).channelPanel.Visible = obj.visibleState(tf);
                elseif fIdx <= numel(app.UI) && isfield(app.UI(fIdx), 'panel') && ...
                        ~isempty(app.UI(fIdx).panel) && isvalid(app.UI(fIdx).panel)
                    app.UI(fIdx).panel.Visible = obj.visibleState(tf);
                end
            catch
            end
        end

        function rowH = channelMinHeightForProfile(~, profile)
            profile = flightdash.util.UIScale.normalizeProfile(profile);
            switch profile
                case flightdash.util.AppConstants.LAYOUT_PROFILE_NARROW
                    rowH = flightdash.util.AppConstants.LAYOUT_CHANNEL_MIN_H_NARROW;
                case flightdash.util.AppConstants.LAYOUT_PROFILE_COMPACT
                    rowH = flightdash.util.AppConstants.LAYOUT_CHANNEL_MIN_H_COMPACT;
                case flightdash.util.AppConstants.LAYOUT_PROFILE_MEDIUM
                    rowH = flightdash.util.AppConstants.LAYOUT_CHANNEL_MIN_H_MEDIUM;
                otherwise
                    rowH = flightdash.util.AppConstants.LAYOUT_CHANNEL_MIN_H_WIDE;
            end
        end

        function placeGridItem(~, h, row, col)
            try
                if isempty(h) || ~isvalid(h), return; end
                h.Layout.Row = row;
                h.Layout.Column = col;
            catch
            end
        end

        function applyResponsiveChannelLayout(obj, app, fIdx, profile)
            try
                if fIdx < 1 || fIdx > numel(app.UI), return; end
                if ~isfield(app.UI(fIdx), 'dataGrid'), return; end
                dg = app.UI(fIdx).dataGrid;
                if isempty(dg) || ~isvalid(dg), return; end

                gridW = NaN;
                try
                    gridPos = getpixelposition(dg, true);
                    if numel(gridPos) >= 4 && isfinite(gridPos(3)) && gridPos(3) > 0
                        gridW = gridPos(3);
                    end
                catch
                end
                if ~isfinite(gridW) || gridW <= 0
                    gridW = app.LastLayoutSize(1);
                end

                widths = obj.computeResponsiveColumnWidths(app, fIdx, profile, gridW, dg);
                if isempty(widths), return; end
                dg.ColumnWidth = widths;

                try
                    if isfield(app.UI(fIdx), 'attMapSplitter')
                        obj.setHandleVisible(app.UI(fIdx).attMapSplitter, isnumeric(widths{2}) && widths{2} > 0);
                    end
                    if isfield(app.UI(fIdx), 'mapInfoSplitter')
                        obj.setHandleVisible(app.UI(fIdx).mapInfoSplitter, isnumeric(widths{4}) && widths{4} > 0);
                    end
                    if isfield(app.UI(fIdx), 'infoPlotSplitter')
                        obj.setHandleVisible(app.UI(fIdx).infoPlotSplitter, isnumeric(widths{6}) && widths{6} > 0);
                    end
                    if isfield(app.UI(fIdx), 'hiSplitter')
                        obj.setHandleVisible(app.UI(fIdx).hiSplitter, isnumeric(widths{8}) && widths{8} > 0);
                    end
                catch
                end
                obj.applyResponsiveRailStates(app, fIdx, widths, profile);
                obj.updatePanelRailSummaries(app, fIdx);
            catch ME
                app.logCaught(ME, 'Layout:channel');
            end
        end

        function widths = computeResponsiveColumnWidths(obj, app, fIdx, profile, gridW, dg)
            profile = flightdash.util.UIScale.normalizeProfile(profile);
            [attD, mapD, infoD, videoD, hMinD] = obj.layoutDesignWidths(profile);

            attW   = flightdash.util.UIScale.pxForProfile(attD, profile);
            mapW   = flightdash.util.UIScale.pxForProfile(mapD, profile);
            infoW  = flightdash.util.UIScale.pxForProfile(infoD, profile);
            videoW = flightdash.util.UIScale.pxForProfile(videoD, profile);
            splitW = flightdash.util.UIScale.pxForProfile(flightdash.util.AppConstants.LAYOUT_SPLITTER_W, profile);
            hMinW  = flightdash.util.UIScale.pxForProfile(hMinD, profile);

            if ~obj.isPanelVisibleForLayout(app, fIdx, 'attitude'), attW = 0; end
            if ~obj.isPanelVisibleForLayout(app, fIdx, 'map'),      mapW = 0; end
            if obj.isPanelVisibleForLayout(app, fIdx, 'attitude')
                attW = obj.resolveManualPanelWidth(app, fIdx, 'attitude', attW, profile);
            end
            if obj.isPanelVisibleForLayout(app, fIdx, 'map')
                mapW = obj.resolveManualPanelWidth(app, fIdx, 'map', mapW, profile);
            end
            if obj.isPanelVisibleForLayout(app, fIdx, 'info')
                infoW = obj.resolveManualPanelWidth(app, fIdx, 'info', infoW, profile);
            end
            if obj.isSplitterRestrictedForProfile(profile), splitW = 0; end
            if ~obj.isPanelVisibleForLayout(app, fIdx, 'video')
                videoW = 0;
            end

            if videoW > 0
                videoW = obj.resolvePreferredVideoWidth(app, fIdx, profile, videoW, dg);
            end

            splitAM = splitW;
            splitMI = splitW;
            splitIH = splitW;
            splitHI = splitW;
            if attW <= 0 || mapW <= 0, splitAM = 0; end
            if mapW <= 0 || infoW <= 0, splitMI = 0; end
            if infoW <= 0, splitIH = 0; end
            if videoW <= 0, splitHI = 0; end

            spacing = 0;
            try, spacing = dg.ColumnSpacing * 8; catch, end
            fixedW = attW + splitAM + mapW + splitMI + infoW + splitIH + splitHI + videoW + spacing;
            deficit = fixedW + hMinW - gridW;
            if isfinite(deficit) && deficit > 0
                minAtt   = flightdash.util.UIScale.pxForProfile(flightdash.util.AppConstants.LAYOUT_ATT_RAIL, profile);
                minInfo  = flightdash.util.UIScale.pxForProfile(flightdash.util.AppConstants.LAYOUT_INFO_RAIL, profile);
                minVideo = flightdash.util.UIScale.pxForProfile(flightdash.util.AppConstants.LAYOUT_VIDEO_RAIL, profile);
                minMap   = flightdash.util.UIScale.pxForProfile(flightdash.util.AppConstants.LAYOUT_MAP_RAIL, profile);

                [videoW, deficit] = obj.shrinkWidth(videoW, minVideo, deficit);
                [mapW,   deficit] = obj.shrinkWidth(mapW,   minMap,   deficit);
                [infoW,  deficit] = obj.shrinkWidth(infoW,  minInfo,  deficit);
                [attW,   deficit] = obj.shrinkWidth(attW,   minAtt,   deficit);
            end

            widths = {max(0, round(attW)), max(0, round(splitAM)), ...
                      max(0, round(mapW)), max(0, round(splitMI)), ...
                      max(0, round(infoW)), max(0, round(splitIH)), ...
                      '1x', max(0, round(splitHI)), max(0, round(videoW))};
        end

        function [attD, mapD, infoD, videoD, hMinD] = layoutDesignWidths(~, profile)
            switch profile
                case flightdash.util.AppConstants.LAYOUT_PROFILE_NARROW
                    attD   = flightdash.util.AppConstants.LAYOUT_ATT_RAIL;
                    mapD   = flightdash.util.AppConstants.LAYOUT_MAP_COMPACT;
                    infoD  = flightdash.util.AppConstants.LAYOUT_INFO_RAIL;
                    videoD = flightdash.util.AppConstants.LAYOUT_VIDEO_RAIL;
                    hMinD  = flightdash.util.AppConstants.LAYOUT_H_MIN_NARROW;
                case flightdash.util.AppConstants.LAYOUT_PROFILE_COMPACT
                    attD   = flightdash.util.AppConstants.LAYOUT_ATT_MEDIUM;
                    mapD   = flightdash.util.AppConstants.LAYOUT_MAP_COMPACT;
                    infoD  = flightdash.util.AppConstants.LAYOUT_INFO_MEDIUM;
                    videoD = flightdash.util.AppConstants.LAYOUT_VIDEO_COMPACT;
                    hMinD  = flightdash.util.AppConstants.LAYOUT_H_MIN_COMPACT;
                case flightdash.util.AppConstants.LAYOUT_PROFILE_MEDIUM
                    attD   = flightdash.util.AppConstants.LAYOUT_ATT_MEDIUM;
                    mapD   = flightdash.util.AppConstants.LAYOUT_MAP_MEDIUM;
                    infoD  = flightdash.util.AppConstants.LAYOUT_INFO_MEDIUM;
                    videoD = flightdash.util.AppConstants.LAYOUT_VIDEO_MEDIUM;
                    hMinD  = flightdash.util.AppConstants.LAYOUT_H_MIN_MEDIUM;
                otherwise
                    attD   = flightdash.util.AppConstants.LAYOUT_ATT_WIDE;
                    mapD   = flightdash.util.AppConstants.LAYOUT_MAP_WIDE;
                    infoD  = flightdash.util.AppConstants.LAYOUT_INFO_WIDE;
                    videoD = flightdash.util.AppConstants.LAYOUT_VIDEO_WIDE;
                    hMinD  = flightdash.util.AppConstants.LAYOUT_H_MIN_WIDE;
            end
        end

        function videoW = resolvePreferredVideoWidth(~, app, fIdx, profile, videoW, dg)
            try
                if app.VideoUserResized(fIdx)
                    manualW = app.ManualVideoWidth(fIdx);
                    if isfinite(manualW) && manualW >= 0
                        videoW = manualW;
                    else
                        cw = dg.ColumnWidth;
                        if numel(cw) >= 9 && isnumeric(cw{9}) && isfinite(cw{9}) && cw{9} > 0
                            videoW = cw{9};
                        end
                    end
                    return;
                end

                prefW = app.PreferredVideoWidth(fIdx);
                if ~isfinite(prefW) || prefW <= 0, return; end

                if strcmp(profile, flightdash.util.AppConstants.LAYOUT_PROFILE_WIDE)
                    capW = flightdash.util.UIScale.pxForProfile(flightdash.util.AppConstants.LAYOUT_VIDEO_WIDE_MAX, profile);
                    videoW = min(max(videoW, prefW), capW);
                else
                    videoW = min(videoW, prefW);
                end
            catch
            end
        end

        function setManualPanelWidth(obj, app, fIdx, panelName, widthVal, profile, gridW)
            try
                widthVal = double(widthVal);
                if ~isfinite(widthVal), return; end
                minW = obj.minimumPanelWidth(panelName, profile);
                maxW = max(minW, gridW * 0.70);
                widthVal = min(max(widthVal, minW), maxW);
                m = app.ManualPanelWidths{fIdx};
                m.(panelName) = round(widthVal);
                app.ManualPanelWidths{fIdx} = m;
            catch ME
                app.logCaught(ME, 'PanelSplitter:setManual');
            end
        end

        function widthVal = resolveManualPanelWidth(obj, app, fIdx, panelName, defaultW, profile)
            widthVal = defaultW;
            try
                if fIdx < 1 || fIdx > numel(app.ManualPanelWidths), return; end
                m = app.ManualPanelWidths{fIdx};
                if isstruct(m) && isfield(m, panelName)
                    candidate = double(m.(panelName));
                    if isfinite(candidate) && candidate >= obj.minimumPanelWidth(panelName, profile)
                        widthVal = candidate;
                    end
                end
            catch
                widthVal = defaultW;
            end
        end

        function minW = minimumPanelWidth(~, panelName, profile)
            switch char(panelName)
                case 'attitude'
                    minD = flightdash.util.AppConstants.LAYOUT_ATT_RAIL;
                case 'map'
                    minD = flightdash.util.AppConstants.LAYOUT_MAP_RAIL;
                case 'info'
                    minD = flightdash.util.AppConstants.LAYOUT_INFO_RAIL;
                otherwise
                    minD = 80;
            end
            minW = flightdash.util.UIScale.pxForProfile(minD, profile);
        end

        function tf = isSplitterRestricted(obj, app)
            try
                [figW, figH] = obj.currentFigureSizePx(app);
                profile = flightdash.util.UIScale.profileForSize(figW, figH);
                tf = obj.isSplitterRestrictedForProfile(profile);
            catch
                tf = false;
            end
        end

        function tf = isSplitterRestrictedForProfile(~, profile)
            profile = flightdash.util.UIScale.normalizeProfile(profile);
            tf = strcmp(profile, flightdash.util.AppConstants.LAYOUT_PROFILE_NARROW);
        end

        function tf = isPanelVisibleForLayout(~, app, fIdx, pnlName)
            tf = true;
            try
                if isfield(app.UI(fIdx), 'PanelVisible') && isfield(app.UI(fIdx).PanelVisible, pnlName)
                    tf = logical(app.UI(fIdx).PanelVisible.(pnlName));
                end
            catch
                tf = true;
            end
        end

        function [val, deficit] = shrinkWidth(~, val, minVal, deficit)
            if deficit <= 0 || val <= 0, return; end
            reducible = max(0, val - minVal);
            take = min(deficit, reducible);
            val = val - take;
            deficit = deficit - take;
        end

        function setHandleVisible(obj, h, isVisible)
            if isempty(h), return; end
            try
                if ~all(isvalid(h)), return; end
                h.Visible = obj.visibleState(isVisible);
            catch
            end
        end

        function applyResponsiveRailStates(obj, app, fIdx, widths, profile)
            try
                if isempty(widths) || numel(widths) < 9, return; end

                obj.setContentRailMode(app, fIdx, 'attitudeContent', 'attitudeRail', ...
                    obj.isRailColumn(widths{1}, flightdash.util.AppConstants.LAYOUT_ATT_RAIL, profile));
                obj.setContentRailMode(app, fIdx, 'mapAltContent', 'mapAltRail', ...
                    obj.isRailColumn(widths{3}, flightdash.util.AppConstants.LAYOUT_MAP_RAIL, profile));
                obj.setContentRailMode(app, fIdx, 'infoContent', 'infoRail', ...
                    obj.isRailColumn(widths{5}, flightdash.util.AppConstants.LAYOUT_INFO_RAIL, profile));
                obj.setContentRailMode(app, fIdx, 'videoContent', 'videoRail', ...
                    obj.isRailColumn(widths{9}, flightdash.util.AppConstants.LAYOUT_VIDEO_RAIL, profile));
            catch ME
                app.logCaught(ME, 'Layout:railState');
            end
        end

        function tf = isRailColumn(~, widthVal, railDesignWidth, profile)
            tf = false;
            if ~isnumeric(widthVal) || isempty(widthVal) || ~isfinite(widthVal) || widthVal <= 0
                return;
            end
            railMax = flightdash.util.UIScale.pxForProfile(railDesignWidth + 16, profile);
            tf = widthVal <= railMax;
        end

        function setContentRailMode(obj, app, fIdx, contentField, railField, useRail)
            if fIdx < 1 || fIdx > numel(app.UI), return; end
            if isfield(app.UI(fIdx), contentField)
                obj.setHandleVisible(app.UI(fIdx).(contentField), ~useRail);
            end
            if isfield(app.UI(fIdx), railField)
                obj.setHandleVisible(app.UI(fIdx).(railField), useRail);
            end
        end

        function updatePanelRailSummaries(obj, app, fIdx)
            try
                if fIdx < 1 || fIdx > numel(app.UI), return; end

                hasData = ~isempty(app.Models(fIdx).rawData) && height(app.Models(fIdx).rawData) > 0;
                if hasData
                    nRows = height(app.Models(fIdx).rawData);
                    idx = max(1, min(nRows, app.Models(fIdx).currentIndex));
                    currTime = obj.modelValueAt(app, fIdx, 'Time', idx, NaN);
                    pitch = obj.modelValueAt(app, fIdx, 'Pitch', idx, NaN);
                    roll  = obj.modelValueAt(app, fIdx, 'Roll', idx, NaN);
                    hdg   = obj.modelValueAt(app, fIdx, 'Heading', idx, NaN);
                    lat   = obj.modelValueAt(app, fIdx, 'Lat', idx, NaN);
                    lon   = obj.modelValueAt(app, fIdx, 'Lon', idx, NaN);
                    alt   = obj.modelValueAt(app, fIdx, 'Alt', idx, NaN);
                else
                    nRows = 0; idx = 0; currTime = NaN;
                    pitch = NaN; roll = NaN; hdg = NaN; lat = NaN; lon = NaN; alt = NaN;
                end

                if isfield(app.UI(fIdx), 'attitudeRail') && ~isempty(app.UI(fIdx).attitudeRail) && isvalid(app.UI(fIdx).attitudeRail)
                    app.UI(fIdx).attitudeRail.Text = sprintf('ATT\nP %s\nR %s\nH %s', ...
                        obj.formatRailNumber('%+.0f', pitch, '--'), ...
                        obj.formatRailNumber('%+.0f', roll, '--'), ...
                        obj.formatRailNumber('%.0f', hdg, '--'));
                end

                if isfield(app.UI(fIdx), 'mapAltRail') && ~isempty(app.UI(fIdx).mapAltRail) && isvalid(app.UI(fIdx).mapAltRail)
                    app.UI(fIdx).mapAltRail.Text = sprintf('MAP\nLat %s\nLon %s\nAlt %s', ...
                        obj.formatRailNumber('%.4f', lat, '--'), ...
                        obj.formatRailNumber('%.4f', lon, '--'), ...
                        obj.formatRailNumber('%.0f', alt, '--'));
                end

                if isfield(app.UI(fIdx), 'infoRail') && ~isempty(app.UI(fIdx).infoRail) && isvalid(app.UI(fIdx).infoRail)
                    if hasData
                        app.UI(fIdx).infoRail.Text = sprintf('INFO\n%s\nRow %d/%d', ...
                            obj.formatRailNumber('%.2fs', currTime, '--'), idx, nRows);
                    else
                        app.UI(fIdx).infoRail.Text = sprintf('INFO\nNo data');
                    end
                end

                if isfield(app.UI(fIdx), 'videoRail') && ~isempty(app.UI(fIdx).videoRail) && isvalid(app.UI(fIdx).videoRail)
                    total = app.VideoSyncState(fIdx).TotalFrames;
                    cur = app.VideoSyncState(fIdx).CurrentFrame;
                    if total > 0
                        if app.VideoSyncState(fIdx).IsSynced
                            syncTxt = 'SYNC';
                        else
                            syncTxt = 'FREE';
                        end
                        app.UI(fIdx).videoRail.Text = sprintf('VID\n%d/%d\n%s', cur, total, syncTxt);
                    else
                        app.UI(fIdx).videoRail.Text = sprintf('VID\nNo AVI');
                    end
                end
            catch ME
                app.logCaught(ME, 'Layout:railSummary');
            end
        end

        function val = modelValueAt(~, app, fIdx, keyName, idx, defaultVal)
            val = defaultVal;
            try
                if isempty(app.Models(fIdx).rawData) || ~isfield(app.Models(fIdx).mappedCols, keyName)
                    return;
                end
                colName = app.Models(fIdx).mappedCols.(keyName);
                if ~ismember(colName, app.Models(fIdx).rawData.Properties.VariableNames)
                    return;
                end
                arr = app.Models(fIdx).rawData.(colName);
                if idx >= 1 && idx <= numel(arr)
                    val = arr(idx);
                end
            catch
                val = defaultVal;
            end
        end

        function txt = formatRailNumber(~, fmt, val, fallback)
            if isnumeric(val) && isscalar(val) && isfinite(val)
                txt = sprintf(fmt, val);
            else
                txt = fallback;
            end
        end
    end

    methods (Access = private)
        function state = visibleState(~, tf)
            if tf
                state = 'on';
            else
                state = 'off';
            end
        end
    end
end
% --- End of root/+flightdash/+view/ResponsiveLayoutManager.m ---

% --- Start of root/+flightdash/+model/ConfigManager.m ---
classdef ConfigManager < handle
    % flightdash.model.ConfigManager
    % Session config import/export facade. The app still owns live state;
    % this class owns file dialogs, markdown/json IO, and config orchestration.

    methods
        function exportConfigInteractive(obj, app)
            filePath = obj.saveSessionConfig(app, 'manual', true);
            if ~isempty(filePath)
                app.notifyUser('Config Export', sprintf('Session config saved:\n%s', filePath), false);
            end
        end

        function importConfigInteractive(obj, app)
            configDir = app.sessionConfigFolder();
            [fname, pname] = uigetfile({'config_*.md;*.md', 'Markdown config (*.md)'}, ...
                'Import session config', configDir);
            if isequal(fname, 0), return; end
            configPath = fullfile(pname, fname);
            try
                obj.importSessionConfig(app, configPath);
                app.notifyUser('Config Import', sprintf('Session config imported:\n%s', configPath), false);
            catch ME
                app.logCaught(ME, 'Config:importInteractive');
                app.notifyUser('Config Import Failed', ME.message, true);
            end
        end

        function autoSaveConfigOnClose(obj, app)
            obj.saveSessionConfig(app, 'autosave', false);
        end

        function filePath = saveSessionConfig(obj, app, saveMode, showErrors)
            if nargin < 3 || isempty(saveMode), saveMode = 'manual'; end
            if nargin < 4, showErrors = false; end
            filePath = '';
            try
                configDir = app.sessionConfigFolder();
                if ~isfolder(configDir), mkdir(configDir); end
                filePath = fullfile(configDir, ['config_' datestr(now, 'yyyymmdd_HHMMSS') '.md']);
                cfg = obj.collectSessionConfig(app, saveMode, filePath);
                obj.writeSessionConfigMarkdown(cfg, filePath);
            catch ME
                filePath = '';
                app.logCaught(ME, ['Config:save:' char(saveMode)]);
                if showErrors
                    app.notifyUser('Config Save Failed', ME.message, true);
                end
            end
        end

        function importSessionConfig(obj, app, configPath)
            cfg = obj.readSessionConfigMarkdown(configPath);
            if ~isfield(cfg, 'Channels'), return; end
            viewMode = app.currentChannelViewMode();
            if isfield(cfg, 'ChannelViewMode')
                viewMode = app.structChar(cfg, 'ChannelViewMode', 'both');
            end

            channels = cfg.Channels;
            for fIdx = 1:min(2, numel(channels))
                ch = channels(fIdx);
                flightPath = app.structChar(ch, 'FlightDataPath', '');
                if ~isempty(flightPath) && isfile(flightPath)
                    app.loadFlightDataFromPath(fIdx, flightPath, true);
                    app.applyStoredMappingIfCompatible(fIdx, ch);
                end
            end

            for fIdx = 1:min(2, numel(channels))
                ch = channels(fIdx);
                videoPath = app.structChar(ch, 'VideoPath', '');
                if ~isempty(videoPath) && isfile(videoPath)
                    app.loadAviFromPathForConfig(fIdx, videoPath);
                    app.restoreVideoSyncStateFromConfig(fIdx, ch);
                end
            end

            for fIdx = 1:min(2, numel(channels))
                ch = channels(fIdx);
                if ~isempty(app.Models(fIdx).rawData)
                    app.restorePlotsFromConfig(fIdx, ch);
                    app.restoreRoisFromConfig(fIdx, ch);
                    app.restoreCurrentIndexFromConfig(fIdx, ch);
                end
            end
            app.setChannelViewMode(viewMode);
        end

        function cfg = collectSessionConfig(~, app, saveMode, filePath)
            if nargin < 3 || isempty(saveMode), saveMode = 'manual'; end
            if nargin < 4, filePath = ''; end
            cfg = struct();
            cfg.SchemaVersion = 1;
            cfg.App = 'FlightDataDashboard';
            cfg.SaveMode = char(saveMode);
            cfg.CreatedAt = datestr(now, 'yyyy-mm-dd HH:MM:SS');
            cfg.ConfigPath = filePath;
            cfg.RootFolder = app.sessionConfigFolder();
            cfg.LayoutProfile = app.currentLayoutProfile();
            cfg.ChannelViewMode = app.currentChannelViewMode();
            cfg.FigurePosition = app.finiteVectorOrEmpty(app.currentFigurePosition());
            cfg.SyncState = app.SyncState;
            channels = repmat(app.emptyChannelConfig(), 1, 2);
            for cfgIdx = 1:2
                channels(cfgIdx) = app.collectChannelConfig(cfgIdx);
            end
            cfg.Channels = channels;
        end

        function writeSessionConfigMarkdown(~, cfg, filePath)
            try
                jsonText = jsonencode(cfg, 'PrettyPrint', true);
            catch
                jsonText = jsonencode(cfg);
            end

            fid = fopen(filePath, 'w');
            if fid < 0
                error('flightdash:Config:OpenFailed', 'Cannot write config file: %s', filePath);
            end
            cleaner = onCleanup(@() fclose(fid));
            fprintf(fid, '# FlightDataDashboard Session Config\n\n');
            fprintf(fid, '- Created: %s\n', cfg.CreatedAt);
            fprintf(fid, '- Save mode: %s\n', cfg.SaveMode);
            fprintf(fid, '- Schema version: %d\n', cfg.SchemaVersion);
            fprintf(fid, '- Root folder: `%s`\n\n', cfg.RootFolder);
            fprintf(fid, '## Files\n\n');
            fprintf(fid, '| Flight | Data file | Video file |\n');
            fprintf(fid, '|---:|---|---|\n');
            for cfgIdx = 1:numel(cfg.Channels)
                fprintf(fid, '| %d | `%s` | `%s` |\n', cfgIdx, ...
                    cfg.Channels(cfgIdx).FlightDataPath, cfg.Channels(cfgIdx).VideoPath);
            end
            fprintf(fid, '\n## Option Mapping Snapshots\n\n');
            for cfgIdx = 1:numel(cfg.Channels)
                fprintf(fid, '### Flight %d - %s\n\n', cfgIdx, cfg.Channels(cfgIdx).OptionFile);
                fprintf(fid, '```text\n%s\n```\n\n', cfg.Channels(cfgIdx).OptionText);
            end
            fprintf(fid, '## Machine-Readable Config\n\n');
            fprintf(fid, '```json\n%s\n```\n', jsonText);
            clear cleaner;
        end

        function cfg = readSessionConfigMarkdown(~, filePath)
            txt = fileread(filePath);
            token = regexp(txt, '```json\s*(.*?)\s*```', 'tokens', 'once');
            if isempty(token)
                error('flightdash:Config:JsonMissing', 'No JSON config block found: %s', filePath);
            end
            cfg = jsondecode(token{1});
        end
    end
end
% --- End of root/+flightdash/+model/ConfigManager.m ---

% --- Start of root/+flightdash/+model/FlightDataLoader.m ---
classdef FlightDataLoader < handle
    % flightdash.model.FlightDataLoader
    % App-independent parser/preprocessor. Methods return model state instead
    % of mutating FlightDataDashboard directly.

    methods
        function modelState = parseFlightData(obj, fIdx, filepath)
            opts = detectImportOptions(filepath);
            opts.DataLines = [2 Inf];
            opts.VariableNamingRule = 'preserve';

            if ~isempty(opts.VariableNames)
                opts.VariableNames{1} = 'time';
            end

            validTypes = {'double', 'single', 'int8', 'uint8', 'int16', 'uint16', ...
                'int32', 'uint32', 'int64', 'uint64'};
            for k = 1:length(opts.VariableTypes)
                if ismember(opts.VariableTypes{k}, validTypes)
                    opts = setvartype(opts, opts.VariableNames{k}, 'double');
                end
            end

            dataTbl = readtable(filepath, opts);
            modelState = obj.applyOptionFile(fIdx, dataTbl, false);

            if any(ismissing(modelState.rawData), 'all')
                modelState.rawData = fillmissing(modelState.rawData, 'linear', 'DataVariables', @isnumeric);
            end
            modelState.rawData = obj.markInvalidGpsAsNaN(modelState.rawData, modelState.mappedCols);
        end

        function modelState = applyOptionFile(obj, fIdx, dataTbl, isMock)
            csvHeaders = dataTbl.Properties.VariableNames;
            numHeaders = length(csvHeaders);
            optFileName = sprintf('option%d.dat', fIdx);

            reqKeys = flightdash.util.AppConstants.REQ_KEYS;
            mappedCols = struct();
            for i = 1:length(reqKeys)
                mappedCols.(reqKeys{i}) = '';
            end

            displayMeta = struct('header', {}, 'unit', {}, 'format', {}, 'scale', {}, 'order', {});

            if isfile(optFileName)
                lines = readlines(optFileName, 'EmptyLineRule', 'skip');
                section = 0;
                for i = 1:length(lines)
                    lineStr = strtrim(lines(i));
                    if startsWith(lineStr, '#'), section = section + 1; continue; end
                    if section == 1
                        parts = split(lineStr, ':');
                        if length(parts) >= 2
                            k = char(strtrim(parts(1)));
                            v = char(strtrim(parts(2)));
                            if isfield(mappedCols, k) && ismember(v, csvHeaders)
                                mappedCols.(k) = v;
                            end
                        end
                    elseif section == 2
                        parts = split(lineStr, ',');
                        if length(parts) >= 4
                            hdr   = char(strtrim(parts(1)));
                            unit  = char(strtrim(parts(2)));
                            fmt   = char(strtrim(parts(3)));
                            order = str2double(strtrim(parts(4)));
                            if length(parts) >= 5
                                scale = str2double(strtrim(parts(5)));
                            else
                                scale = 1.0;
                            end
                            if ~isnan(order) && ismember(hdr, csvHeaders)
                                displayMeta(end+1) = struct('header', hdr, 'unit', unit, ...
                                    'format', fmt, 'scale', scale, 'order', order); %#ok<AGROW>
                            end
                        end
                    end
                end
            end

            for i = 1:length(reqKeys)
                keyName = reqKeys{i};
                if isempty(mappedCols.(keyName))
                    inferredCol = obj.inferRequiredColumn(keyName, csvHeaders);
                    if ~isempty(inferredCol)
                        mappedCols.(keyName) = inferredCol;
                    end
                end
            end

            if isMock
                for i = 1:length(reqKeys)
                    keyName = reqKeys{i};
                    if isempty(mappedCols.(keyName)) && (i <= numHeaders)
                        mappedCols.(keyName) = csvHeaders{i};
                    end
                end
            else
                obj.validateRequiredColumns(dataTbl, mappedCols, fIdx);
            end

            if isempty(displayMeta)
                for i = 1:numHeaders
                    displayMeta(end+1) = struct('header', csvHeaders{i}, 'unit', '-', ...
                        'format', '%.6f', 'scale', 1.0, 'order', i); %#ok<AGROW>
                end
            else
                orders = [displayMeta.order];
                if (length(unique(orders)) == length(orders)) && ...
                        (min(orders) == 1) && (max(orders) == length(orders))
                    [~, sortIdx] = sort([displayMeta.order]);
                    displayMeta = displayMeta(sortIdx);
                else
                    for i = 1:length(displayMeta)
                        displayMeta(i).order = i;
                    end
                end

                existingHeaders = {displayMeta.header};
                missingHeaders = setdiff(csvHeaders, existingHeaders, 'stable');
                for i = 1:length(missingHeaders)
                    displayMeta(end+1) = struct('header', missingHeaders{i}, 'unit', '-', ...
                        'format', '%.6f', 'scale', 1.0, 'order', length(displayMeta) + i); %#ok<AGROW>
                end
            end

            for i = 1:length(displayMeta)
                if isMock, displayMeta(i).scale = 1.0; end
                colName = displayMeta(i).header;
                if displayMeta(i).scale ~= 1.0
                    dataTbl.(colName) = dataTbl.(colName) * displayMeta(i).scale;
                end
            end

            modelState = struct();
            modelState.rawData = dataTbl;
            modelState.mappedCols = mappedCols;
            modelState.displayMeta = displayMeta;
            modelState.selectedRow = 1;
            modelState.isMockData = isMock;
            if ~isMock
                obj.validateRequiredColumnData(modelState.rawData, modelState.mappedCols);
            end
        end

        function dataTbl = markInvalidGpsAsNaN(~, dataTbl, mappedCols)
            try
                if isfield(mappedCols, 'Lat') && isfield(mappedCols, 'Lon')
                    if isempty(mappedCols.Lat) || isempty(mappedCols.Lon), return; end
                    lats = dataTbl.(mappedCols.Lat);
                    lons = dataTbl.(mappedCols.Lon);
                    invalid = ((lats == 0) & (lons == 0)) | ~isfinite(lats) | ~isfinite(lons);
                    if any(invalid)
                        lats(invalid) = NaN;
                        lons(invalid) = NaN;
                        dataTbl.(mappedCols.Lat) = lats;
                        dataTbl.(mappedCols.Lon) = lons;
                    end
                end
            catch
            end
        end

        function modelState = generateMockFlightData(obj, fIdx, bounds)
            latRange = bounds.maxLat - bounds.minLat;
            lonRange = bounds.maxLon - bounds.minLon;
            if latRange <= 0, latRange = 0.1; end
            if lonRange <= 0, lonRange = 0.1; end

            minLat = bounds.minLat;
            maxLat = bounds.maxLat;
            minLon = bounds.minLon;
            maxLon = bounds.maxLon;

            currLat = minLat + latRange / 2 + (fIdx * 0.02);
            currLon = minLon + lonRange / 2 - (fIdx * 0.02);
            currAlt = 5000 + (fIdx * 500);
            currHdg = (rand() * 360) - 180;
            currRoll = 0;
            currPitch = 5;
            speed = min(latRange, lonRange) * 0.005;

            N = flightdash.util.AppConstants.MOCK_STEP_COUNT;
            time_s = zeros(N, 1);
            lat_deg = zeros(N, 1);
            lon_deg = zeros(N, 1);
            alt_ft = zeros(N, 1);
            hdg_deg = zeros(N, 1);
            roll_deg = zeros(N, 1);
            pitch_deg = zeros(N, 1);

            for i = 1:N
                time_s(i) = i-1;
                lat_deg(i) = currLat;
                lon_deg(i) = currLon;
                alt_ft(i) = currAlt;
                hdg_deg(i) = currHdg;
                roll_deg(i) = currRoll;
                pitch_deg(i) = currPitch;

                if i > 50 && i < 100
                    currRoll = min(currRoll + 2, 45);
                    currHdg = currHdg + currRoll * 0.1;
                elseif i >= 100 && i < 130
                    currRoll = currRoll * 0.9;
                elseif i > 150
                    currRoll = max(currRoll - 2, -45);
                    currHdg = currHdg + currRoll * 0.1;
                else
                    currRoll = currRoll * 0.9;
                end

                if currHdg > 180, currHdg = currHdg - 360; end
                if currHdg <= -180, currHdg = currHdg + 360; end

                if i < 80
                    currPitch = 5;
                    currAlt = currAlt + 20;
                elseif i > 120
                    currPitch = -3;
                    currAlt = currAlt - 15;
                else
                    currPitch = 0;
                end

                currPitch = currPitch + (rand() - 0.5) * 1;
                currRoll = currRoll + (rand() - 0.5) * 2;

                if currPitch > 180, currPitch = currPitch - 360; end
                if currPitch <= -180, currPitch = currPitch + 360; end
                if currRoll > 180, currRoll = currRoll - 360; end
                if currRoll <= -180, currRoll = currRoll + 360; end

                mathAngle = (90 - currHdg) * pi / 180;
                currLon = currLon + cos(mathAngle) * speed;
                currLat = currLat + sin(mathAngle) * speed;

                if currLat > maxLat
                    currLat = maxLat - (currLat - maxLat);
                    currHdg = -currHdg;
                elseif currLat < minLat
                    currLat = minLat + (minLat - currLat);
                    currHdg = -currHdg;
                end
                if currLon > maxLon
                    currLon = maxLon - (currLon - maxLon);
                    currHdg = 180 - currHdg;
                elseif currLon < minLon
                    currLon = minLon + (minLon - currLon);
                    currHdg = 180 - currHdg;
                end

                if currHdg > 180, currHdg = currHdg - 360; end
                if currHdg <= -180, currHdg = currHdg + 360; end
            end

            optFileName = sprintf('option%d.dat', fIdx);
            baseKeys = flightdash.util.AppConstants.REQ_KEYS;
            varNames = baseKeys;
            if isfile(optFileName)
                lines = readlines(optFileName, 'EmptyLineRule', 'skip');
                section = 0;
                for idxLine = 1:length(lines)
                    lineStr = strtrim(lines(idxLine));
                    if startsWith(lineStr, '#'), section = section + 1; continue; end
                    if section == 1
                        parts = split(lineStr, ':');
                        if length(parts) >= 2
                            k = char(strtrim(parts(1)));
                            v = char(strtrim(parts(2)));
                            matchIdx = find(strcmp(baseKeys, k));
                            if ~isempty(matchIdx), varNames{matchIdx} = v; end
                        end
                    end
                end
            end

            mockTbl = table(time_s, roll_deg, pitch_deg, hdg_deg, alt_ft, lat_deg, lon_deg, ...
                'VariableNames', varNames);
            modelState = obj.applyOptionFile(fIdx, mockTbl, true);
        end

        function [bounds, altBounds] = calculateBounds(~, rawData, mappedCols, coastlineData, fixedAreaBounds, currentBounds, currentAltBounds)
            if nargin < 6 || isempty(currentBounds)
                currentBounds = struct('minLat', 0, 'maxLat', 0, 'minLon', 0, 'maxLon', 0, 'isValid', false);
            end
            if nargin < 7 || isempty(currentAltBounds)
                currentAltBounds = struct('minAlt', 0, 'maxAlt', 0);
            end

            bounds = currentBounds;
            altBounds = currentAltBounds;
            minLat = 90; maxLat = -90; minLon = 180; maxLon = -180;
            minAlt = 99999; maxAlt = -99999; hasData = false; hasFlightGeo = false;

            if ~isempty(coastlineData)
                minLat = min(minLat, min(coastlineData(:,1))); maxLat = max(maxLat, max(coastlineData(:,1)));
                minLon = min(minLon, min(coastlineData(:,2))); maxLon = max(maxLon, max(coastlineData(:,2)));
                hasData = true;
            end

            if ~isempty(rawData) && height(rawData) > 0 && isstruct(mappedCols) && ...
                    isfield(mappedCols, 'Lat') && isfield(mappedCols, 'Lon') && isfield(mappedCols, 'Alt') && ...
                    ismember(mappedCols.Lat, rawData.Properties.VariableNames) && ...
                    ismember(mappedCols.Lon, rawData.Properties.VariableNames) && ...
                    ismember(mappedCols.Alt, rawData.Properties.VariableNames)
                lats = rawData.(mappedCols.Lat);
                lons = rawData.(mappedCols.Lon);
                alts = rawData.(mappedCols.Alt);

                validGeo = isfinite(lats) & isfinite(lons);
                if any(validGeo)
                    minLat = min(lats(validGeo));
                    maxLat = max(lats(validGeo));
                    minLon = min(lons(validGeo));
                    maxLon = max(lons(validGeo));
                    hasFlightGeo = true;
                end
                validAlt = isfinite(alts);
                if any(validAlt)
                    minAlt = min(minAlt, min(alts(validAlt)));
                    maxAlt = max(maxAlt, max(alts(validAlt)));
                end
                hasData = true;
            end

            if ~isempty(fixedAreaBounds)
                bounds.minLat = fixedAreaBounds.minLat;
                bounds.maxLat = fixedAreaBounds.maxLat;
                bounds.minLon = fixedAreaBounds.minLon;
                bounds.maxLon = fixedAreaBounds.maxLon;
                bounds.isValid = true;
            elseif hasFlightGeo
                latPad = max((maxLat - minLat) * 0.05, 0.01);
                lonPad = max((maxLon - minLon) * 0.05, 0.01);
                bounds.minLat = minLat - latPad; bounds.maxLat = maxLat + latPad;
                bounds.minLon = minLon - lonPad; bounds.maxLon = maxLon + lonPad;
                bounds.isValid = true;
            elseif hasData && isfinite(minLat) && isfinite(maxLat) && isfinite(minLon) && isfinite(maxLon) && ...
                    minLat <= maxLat && minLon <= maxLon
                latPad = max((maxLat - minLat) * 0.05, 0.01);
                lonPad = max((maxLon - minLon) * 0.05, 0.01);
                bounds.minLat = minLat - latPad; bounds.maxLat = maxLat + latPad;
                bounds.minLon = minLon - lonPad; bounds.maxLon = maxLon + lonPad;
                bounds.isValid = true;
            end

            if hasData && isfinite(minAlt) && isfinite(maxAlt)
                altPad = max((maxAlt - minAlt) * 0.1, 100);
                altBounds.minAlt = minAlt - altPad;
                altBounds.maxAlt = maxAlt + altPad;
            end
        end
    end

    methods (Access = private)
        function validateRequiredColumns(~, dataTbl, mappedCols, fIdx)
            reqKeys = flightdash.util.AppConstants.REQ_KEYS;
            vars = dataTbl.Properties.VariableNames;
            missing = {};
            for i = 1:numel(reqKeys)
                keyName = reqKeys{i};
                if ~isfield(mappedCols, keyName) || isempty(mappedCols.(keyName)) || ...
                        ~ismember(mappedCols.(keyName), vars)
                    missing{end+1} = keyName; %#ok<AGROW>
                end
            end
            if ~isempty(missing)
                error('flightdash:DataMapping:MissingRequiredColumn', ...
                    'Required flight-data columns were not mapped: %s. Check option%d.dat or file headers.', ...
                    strjoin(missing, ', '), fIdx);
            end
        end

        function validateRequiredColumnData(~, dataTbl, mappedCols)
            timeVals = dataTbl.(mappedCols.Time);
            if ~isnumeric(timeVals) || numel(timeVals) < 2 || any(~isfinite(timeVals)) || ...
                    any(diff(timeVals) <= 0)
                error('flightdash:DataMapping:InvalidTimeColumn', ...
                    'Mapped Time column must be numeric, finite, and strictly increasing.');
            end

            latVals = dataTbl.(mappedCols.Lat);
            lonVals = dataTbl.(mappedCols.Lon);
            finiteLat = latVals(isfinite(latVals));
            finiteLon = lonVals(isfinite(lonVals));
            if ~isnumeric(latVals) || ~isnumeric(lonVals) || isempty(finiteLat) || isempty(finiteLon) || ...
                    any(finiteLat < -90 | finiteLat > 90) || any(finiteLon < -180 | finiteLon > 180)
                error('flightdash:DataMapping:InvalidGeoColumns', ...
                    'Mapped Lat/Lon columns must be numeric and within latitude/longitude bounds.');
            end
        end

        function colName = inferRequiredColumn(obj, reqKey, csvHeaders)
            colName = '';
            candidates = obj.requiredColumnCandidates(reqKey);
            if isempty(candidates), return; end
            normalizedHeaders = cell(size(csvHeaders));
            for hIdx = 1:numel(csvHeaders)
                normalizedHeaders{hIdx} = obj.normalizeHeaderName(csvHeaders{hIdx});
            end
            for cIdx = 1:numel(candidates)
                normalizedCandidate = obj.normalizeHeaderName(candidates{cIdx});
                matchIdx = find(strcmp(normalizedHeaders, normalizedCandidate), 1, 'first');
                if ~isempty(matchIdx)
                    colName = csvHeaders{matchIdx};
                    return;
                end
            end
        end

        function candidates = requiredColumnCandidates(~, reqKey)
            switch char(reqKey)
                case 'Time'
                    candidates = {'time_s', 'time', 'times', 'timestamp', 'elapsed_time', 'elapsedtime', 'seconds', 'sec', 't'};
                case 'Roll'
                    candidates = {'Roll', 'roll_deg', 'rolldeg', 'phi'};
                case 'Pitch'
                    candidates = {'Pitch', 'pitch_deg', 'pitchdeg', 'theta'};
                case 'Heading'
                    candidates = {'Heading', 'heading_deg', 'headingdeg', 'Yaw', 'yaw_deg', 'yawdeg', 'CourseAngle', 'course_angle', 'course', 'track', 'psi'};
                case 'Alt'
                    candidates = {'Altitude', 'altitude_m', 'altitude_ft', 'alt', 'PressAltitude', 'press_altitude', 'baro_altitude', 'height'};
                case 'Lat'
                    candidates = {'Latitude', 'latitude_deg', 'lat_deg', 'lat', 'gps_lat', 'gpslatitude'};
                case 'Lon'
                    candidates = {'Longitude', 'longitude_deg', 'lon_deg', 'lon', 'lng', 'long', 'gps_lon', 'gpslongitude'};
                otherwise
                    candidates = {};
            end
        end

        function normalized = normalizeHeaderName(~, value)
            normalized = lower(regexprep(char(value), '[^A-Za-z0-9]', ''));
        end
    end
end
% --- End of root/+flightdash/+model/FlightDataLoader.m ---

% --- Start of root/+flightdash/+model/FlightModeAnalyzer.m ---
classdef FlightModeAnalyzer
    % flightdash.model.FlightModeAnalyzer
    % Pure flight-mode band extraction from loaded flight-log tables.

    methods (Static)
        function bands = computeBands(mappedCols, rawData)
            bands = struct('Start', {}, 'End', {}, 'Mode', {}, 'Color', {});
            if isempty(rawData) || ~isfield(mappedCols, 'Time'), return; end
            timeCol = mappedCols.Time;
            if ~ismember(timeCol, rawData.Properties.VariableNames), return; end
            times = rawData.(timeCol);
            times = times(:);
            if numel(times) < 2, return; end

            alt = flightdash.model.FlightModeAnalyzer.seriesByKey(mappedCols, rawData, 'Alt', zeros(size(times)));
            roll = flightdash.model.FlightModeAnalyzer.seriesByKey(mappedCols, rawData, 'Roll', zeros(size(times)));
            alt = flightdash.model.FlightModeAnalyzer.normalizeSeries(alt, numel(times), 0);
            roll = flightdash.model.FlightModeAnalyzer.normalizeSeries(roll, numel(times), 0);
            if max(abs(roll), [], 'omitnan') < 7
                roll = roll * 180 / pi;
            end
            speed = flightdash.model.FlightModeAnalyzer.seriesByCandidates(rawData, ...
                {'GroundSpeed', 'Ground_Speed', 'Speed', 'Airspeed', 'IndicatedAirSpeed'}, zeros(size(times)));
            speed = flightdash.model.FlightModeAnalyzer.normalizeSeries(speed, numel(times), 0);

            labels = flightdash.model.FlightModeAnalyzer.labelsFromData(rawData, numel(times));
            if isempty(labels)
                dtRaw = diff(times);
                dtMed = median(dtRaw(dtRaw > 0 & isfinite(dtRaw)));
                if isempty(dtMed) || ~isfinite(dtMed), dtMed = 1; end
                dt = [dtRaw; dtMed];
                dt(dt <= 0 | ~isfinite(dt)) = dtMed;
                if isempty(dt) || any(~isfinite(dt)), dt = ones(size(times)); end
                vz = [0; diff(alt) ./ dt(1:end-1)];

                labels = repmat({'Cruise'}, numel(times), 1);
                labels(abs(roll) > 12) = {'Turn'};
                labels(speed < 2) = {'Loiter'};
                labels(vz > 0.35) = {'Climb'};
                labels(vz < -0.35) = {'Descent'};
                labels(times < times(1) + 2) = {'Start'};
            end

            startIdx = 1;
            for k = 2:numel(labels)
                if ~strcmp(labels{k}, labels{startIdx})
                    bands(end+1) = flightdash.model.FlightModeAnalyzer.modeBand(times(startIdx), times(k-1), labels{startIdx}); %#ok<AGROW>
                    startIdx = k;
                end
            end
            bands(end+1) = flightdash.model.FlightModeAnalyzer.modeBand(times(startIdx), times(end), labels{startIdx});
        end

        function labels = labelsFromData(rawData, nRows)
            labels = {};
            try
                vars = rawData.Properties.VariableNames;
                candidates = {'FlightMode', 'Flight_Mode', 'VehicleMode', 'Vehicle_Mode', ...
                    'Mode', 'MainState', 'Main_State', 'NavState', 'Nav_State'};
                modeCol = '';
                for k = 1:numel(candidates)
                    idx = find(strcmpi(vars, candidates{k}), 1);
                    if ~isempty(idx)
                        modeCol = vars{idx};
                        break;
                    end
                end
                if isempty(modeCol)
                    lowerVars = lower(vars);
                    idx = find(contains(lowerVars, 'flightmode') | contains(lowerVars, 'flight_mode') | ...
                        contains(lowerVars, 'navstate') | contains(lowerVars, 'mainstate'), 1);
                    if ~isempty(idx), modeCol = vars{idx}; end
                end
                if isempty(modeCol), return; end

                col = rawData.(modeCol);
                if isnumeric(col) || islogical(col)
                    labels = arrayfun(@(v) flightdash.model.FlightModeAnalyzer.codeLabel(v), col(:), 'UniformOutput', false);
                elseif iscategorical(col)
                    labels = cellstr(col(:));
                elseif isstring(col)
                    labels = cellstr(col(:));
                elseif iscell(col)
                    labels = cellfun(@(v) char(string(v)), col(:), 'UniformOutput', false);
                else
                    labels = cellstr(string(col(:)));
                end
                labels = labels(:);
                labels(cellfun(@isempty, labels)) = {'Unknown'};
                if numel(labels) ~= nRows
                    labels = {};
                end
            catch
                labels = {};
            end
        end

        function label = codeLabel(value)
            if isempty(value) || ~isfinite(value)
                label = 'Unknown';
            else
                label = sprintf('Mode %g', value);
            end
        end

        function band = modeBand(t0, t1, modeName)
            band = struct('Start', t0, 'End', t1, 'Mode', modeName, 'Color', [0.55 0.55 0.55]);
            switch char(modeName)
                case 'Start',   band.Color = [0.25 0.55 0.95];
                case 'Climb',   band.Color = [0.15 0.65 0.35];
                case 'Descent', band.Color = [0.90 0.55 0.15];
                case 'Turn',    band.Color = [0.55 0.25 0.75];
                case 'Loiter',  band.Color = [0.20 0.70 0.85];
                otherwise,      band.Color = [0.40 0.55 0.20];
            end
        end
    end

    methods (Static, Access = private)
        function y = seriesByKey(mappedCols, rawData, keyName, defaultVal)
            y = defaultVal(:);
            try
                if isfield(mappedCols, keyName)
                    colName = mappedCols.(keyName);
                    if ismember(colName, rawData.Properties.VariableNames)
                        y = rawData.(colName);
                        if isnumeric(y) || islogical(y)
                            y = double(y(:));
                        else
                            y = defaultVal(:);
                        end
                    end
                end
            catch
                y = defaultVal(:);
            end
        end

        function y = seriesByCandidates(rawData, candidates, defaultVal)
            y = defaultVal(:);
            try
                vars = rawData.Properties.VariableNames;
                for k = 1:numel(candidates)
                    idx = find(strcmpi(vars, candidates{k}), 1);
                    if ~isempty(idx)
                        y = rawData.(vars{idx});
                        if isnumeric(y) || islogical(y)
                            y = double(y(:));
                        else
                            y = defaultVal(:);
                        end
                        return;
                    end
                end
            catch
                y = defaultVal(:);
            end
        end

        function y = normalizeSeries(y, nRows, fillValue)
            if isempty(y) || ~isnumeric(y)
                y = repmat(fillValue, nRows, 1);
                return;
            end
            y = double(y(:));
            if numel(y) ~= nRows
                y = repmat(fillValue, nRows, 1);
            end
        end
    end
end
% --- End of root/+flightdash/+model/FlightModeAnalyzer.m ---

% --- Start of root/+flightdash/+model/PlaybackStateModel.m ---
classdef PlaybackStateModel < handle
    % flightdash.model.PlaybackStateModel
    % Per-channel guards and coalesced frame request state.

    properties (SetAccess = private)
        IsUpdating logical = false
        InGoToFrame logical = false
        IsDecoding logical = false
        PendingFrame double = NaN
        PendingMode char = ''
    end

    methods
        function setUpdating(obj, state)
            obj.IsUpdating = logical(state);
        end

        function setGoToFrame(obj, state)
            obj.InGoToFrame = logical(state);
        end

        function setDecoding(obj, state)
            obj.IsDecoding = logical(state);
        end

        function setPendingRequest(obj, frameNo, mode)
            obj.PendingFrame = double(frameNo);
            if nargin < 3 || isempty(mode)
                mode = '';
            end
            obj.PendingMode = char(mode);
        end

        function [hasPending, frameNo, mode] = peekPendingRequest(obj)
            hasPending = ~isnan(obj.PendingFrame);
            frameNo = obj.PendingFrame;
            mode = obj.PendingMode;
        end

        function [hasPending, frameNo, mode] = consumePendingRequest(obj)
            [hasPending, frameNo, mode] = obj.peekPendingRequest();
            obj.clearPendingRequest();
        end

        function clearPendingRequest(obj)
            obj.PendingFrame = NaN;
            obj.PendingMode = '';
        end

        function reset(obj)
            obj.IsUpdating = false;
            obj.InGoToFrame = false;
            obj.IsDecoding = false;
            obj.clearPendingRequest();
        end
    end
end
% --- End of root/+flightdash/+model/PlaybackStateModel.m ---

% --- Start of root/+flightdash/+controller/PannerController.m ---
classdef PannerController < handle
    % flightdash.controller.PannerController
    % Owns compact range bar commands and handle-drag lifecycle.

    properties (Access = private)
        App
        Listeners cell = {}
        IsDragging logical = false
        DragFIdx double = 0
        DragSide char = ''
    end

    methods
        function obj = PannerController(app)
            obj.App = app;
            obj.subscribeEvents();
        end

        function subscribeEvents(obj)
            EB = @flightdash.util.EventBus.subscribe;
            obj.Listeners{end+1} = EB('PannerToggled', @(~,d) obj.togglePanner(d.ChannelIdx));
            obj.Listeners{end+1} = EB('PannerClicked', @(~,d) obj.onPannerClicked(d.ChannelIdx));
            obj.Listeners{end+1} = EB('PannerRangeChanged', @(~,d) obj.onRangeChanged(d.ChannelIdx));
            obj.Listeners{end+1} = EB('PannerResetRequested', @(~,d) obj.resetRange(d.ChannelIdx));
        end

        function togglePanner(obj, fIdx)
            app = obj.App;
            try
                if ~isfield(app.UI(fIdx), 'plotShellGrid') || ~isvalid(app.UI(fIdx).plotShellGrid), return; end
                if ~isfield(app.UI(fIdx), 'pannerPanel') || isempty(app.UI(fIdx).pannerPanel) || ~isvalid(app.UI(fIdx).pannerPanel), return; end
                curr = false;
                if isfield(app.UI(fIdx), 'PannerVisible'), curr = logical(app.UI(fIdx).PannerVisible); end
                next = ~curr;
                app.UI(fIdx).PannerVisible = next;
                app.UI(fIdx).pannerPanel.Visible = app.visibleState(next);
                rh = app.UI(fIdx).plotShellGrid.RowHeight;
                if next
                    rh{3} = flightdash.util.UIScale.px(58);
                    app.refreshPanner(fIdx);
                else
                    rh{3} = 0;
                end
                app.UI(fIdx).plotShellGrid.RowHeight = rh;
            catch ME
                app.logCaught(ME, 'Panner:toggle');
            end
        end

        function onPannerClicked(obj, fIdx)
            app = obj.App;
            try
                ax = app.UI(fIdx).pannerAxes;
                pt = ax.CurrentPoint;
                clickTime = pt(1, 1);
                timeCol = app.Models(fIdx).mappedCols.Time;
                times = app.Models(fIdx).rawData.(timeCol);
                xlims = app.currentPlotXLim(fIdx, times);
                minGap = max(eps, (times(end) - times(1)) * 0.001);
                clickTime = max(times(1), min(times(end), clickTime));
                if abs(clickTime - xlims(1)) <= abs(clickTime - xlims(2))
                    clickTime = min(clickTime, xlims(2) - minGap);
                    obj.setCurrentTabXLim(fIdx, clickTime, xlims(2));
                else
                    clickTime = max(clickTime, xlims(1) + minGap);
                    obj.setCurrentTabXLim(fIdx, xlims(1), clickTime);
                end
            catch ME
                app.logCaught(ME, 'Panner:clicked');
            end
        end

        function startHandleDrag(obj, fIdx, side, event)
            app = obj.App;
            try
                if nargin >= 4 && ~isempty(event)
                    try
                        if isprop(event, 'Button') && event.Button ~= 1
                            return;
                        end
                    catch
                    end
                end
                if isempty(app.Models(fIdx).rawData), return; end
                obj.IsDragging = true;
                obj.DragFIdx = fIdx;
                obj.DragSide = char(side);
                if isprop(app.UIFigure, 'Pointer'), app.UIFigure.Pointer = 'left-right'; end
                app.UIFigure.WindowButtonMotionFcn = @(~,~) obj.handleDragMotion();
                app.UIFigure.WindowButtonUpFcn = @(~,~) obj.stopHandleDrag();
            catch ME
                app.logCaught(ME, 'PannerHandle:start');
            end
        end

        function handleDragMotion(obj)
            app = obj.App;
            if ~obj.IsDragging, return; end
            try
                fIdx = obj.DragFIdx;
                if fIdx < 1 || fIdx > numel(app.UI), return; end
                ax = app.UI(fIdx).pannerAxes;
                if isempty(ax) || ~isvalid(ax), return; end
                pt = ax.CurrentPoint;
                newTime = pt(1, 1);
                timeCol = app.Models(fIdx).mappedCols.Time;
                times = app.Models(fIdx).rawData.(timeCol);
                xlims = app.currentPlotXLim(fIdx, times);
                minGap = max(eps, (times(end) - times(1)) * 0.001);
                newTime = max(times(1), min(times(end), newTime));
                if strcmp(obj.DragSide, 'left')
                    newTime = min(newTime, xlims(2) - minGap);
                    obj.setCurrentTabXLim(fIdx, newTime, xlims(2));
                else
                    newTime = max(newTime, xlims(1) + minGap);
                    obj.setCurrentTabXLim(fIdx, xlims(1), newTime);
                end
                drawnow limitrate nocallbacks;
            catch ME
                app.logCaught(ME, 'PannerHandle:motion');
            end
        end

        function stopHandleDrag(obj)
            app = obj.App;
            try
                obj.IsDragging = false;
                obj.DragFIdx = 0;
                obj.DragSide = '';
                if isempty(app) || ~isvalid(app), return; end
                if ~isempty(app.UIFigure) && isvalid(app.UIFigure)
                    app.UIFigure.WindowButtonMotionFcn = '';
                    app.UIFigure.WindowButtonUpFcn = '';
                    if isprop(app.UIFigure, 'Pointer'), app.UIFigure.Pointer = 'arrow'; end
                end
                drawnow limitrate;
            catch ME
                try
                    if ~isempty(app) && isvalid(app)
                        app.logCaught(ME, 'PannerHandle:stop');
                    end
                catch
                end
            end
        end

        function onRangeChanged(obj, fIdx)
            app = obj.App;
            try
                fromVal = app.UI(fIdx).pannerFrom.Value;
                toVal = app.UI(fIdx).pannerTo.Value;
                obj.setCurrentTabXLim(fIdx, fromVal, toVal);
            catch ME
                app.logCaught(ME, 'Panner:range');
            end
        end

        function resetRange(obj, fIdx)
            app = obj.App;
            try
                timeCol = app.Models(fIdx).mappedCols.Time;
                times = app.Models(fIdx).rawData.(timeCol);
                obj.setCurrentTabXLim(fIdx, times(1), times(end));
            catch ME
                app.logCaught(ME, 'Panner:reset');
            end
        end

        function setCurrentTabXLim(obj, fIdx, fromVal, toVal)
            app = obj.App;
            try
                if isempty(app.Models(fIdx).rawData), return; end
                timeCol = app.Models(fIdx).mappedCols.Time;
                times = app.Models(fIdx).rawData.(timeCol);
                if isempty(times), return; end
                fromVal = max(times(1), min(times(end), fromVal));
                toVal = max(times(1), min(times(end), toVal));
                if toVal <= fromVal
                    toVal = min(times(end), fromVal + max(eps, (times(end) - times(1)) * 0.05));
                    fromVal = max(times(1), min(fromVal, toVal - eps));
                end
                tabIdx = app.currentPlotTabIndex(fIdx);
                if ~isempty(tabIdx) && ~isempty(app.UI(fIdx).plotAxes{tabIdx})
                    app.IsProgrammaticXLim(fIdx) = true;
                    cleanup_ = onCleanup(@() obj.resetProgrammaticXLim(fIdx)); %#ok<NASGU>
                    for k = 1:numel(app.UI(fIdx).plotAxes{tabIdx})
                        ax = app.UI(fIdx).plotAxes{tabIdx}{k};
                        if ~isempty(ax) && isvalid(ax), ax.XLim = [fromVal, toVal]; end
                    end
                    clear cleanup_;
                end
                app.updatePannerViewport(fIdx);
            catch ME
                app.IsProgrammaticXLim(fIdx) = false;
                app.logCaught(ME, 'Panner:setXLim');
            end
        end

        function resetProgrammaticXLim(obj, fIdx)
            app = obj.App;
            try
                if fIdx >= 1 && fIdx <= numel(app.IsProgrammaticXLim)
                    app.IsProgrammaticXLim(fIdx) = false;
                end
            catch ME
                app.logCaught(ME, 'Panner:resetProgrammaticXLim');
            end
        end

        function delete(obj)
            obj.stopHandleDrag();
            for k = 1:numel(obj.Listeners)
                try
                    if isvalid(obj.Listeners{k}), delete(obj.Listeners{k}); end
                catch
                end
            end
            obj.Listeners = {};
        end
    end
end
% --- End of root/+flightdash/+controller/PannerController.m ---

% --- Start of root/+flightdash/+controller/PlotController.m ---
classdef PlotController < handle
    % flightdash.controller.PlotController
    % Owns Plot/Tab EventBus routing.

    properties (Access = private)
        App
        Listeners cell = {}
    end

    methods
        function obj = PlotController(app)
            obj.App = app;
            obj.subscribeEvents();
        end

        function subscribeEvents(obj)
            EB = @flightdash.util.EventBus.subscribe;
            obj.Listeners{end+1} = EB('PlotSelected',           @(~,d) obj.onPlotSelected(d));
            obj.Listeners{end+1} = EB('PlotTabAddRequested',    @(~,d) obj.onAddTab(d));
            obj.Listeners{end+1} = EB('PlotTabClearRequested',  @(~,d) obj.onClearTab(d));
            obj.Listeners{end+1} = EB('TabChanged',             @(~,d) obj.onTabChanged(d));
            obj.Listeners{end+1} = EB('PlotVisibilityChanged',  @(~,d) obj.onPlotVisibility(d));
            obj.Listeners{end+1} = EB('PlotManagerSelected',    @(~,d) obj.onPlotManagerSelected(d));
            obj.Listeners{end+1} = EB('PlotDetailChanged',      @(~,d) obj.onPlotDetailChanged(d));
            obj.Listeners{end+1} = EB('PlotAxisChanged',        @(~,d) obj.onPlotAxisChanged(d));
            obj.Listeners{end+1} = EB('PlotManagerToggled',     @(~,d) obj.onPlotManagerToggled(d));
            obj.Listeners{end+1} = EB('PlotDetailsToggled',     @(~,d) obj.onPlotDetailsToggled(d));
        end

        function onPlotSelected(obj, d),   obj.App.plotSelectedVariable(d.ChannelIdx); end
        function onAddTab(obj, d),         obj.App.addPlotTab(d.ChannelIdx); end
        function onClearTab(obj, d),       obj.App.clearCurrentTab(d.ChannelIdx); end
        function onTabChanged(obj, d),     obj.App.updateTabTimeLines(d.ChannelIdx); end
        function onPlotVisibility(obj, d), obj.App.onPlotVisibilityChanged(d.ChannelIdx, d.Payload); end
        function onPlotManagerSelected(obj, d), obj.App.onPlotManagerSelected(d.ChannelIdx, d.Payload); end
        function onPlotDetailChanged(obj, d), obj.App.onPlotDetailChanged(d.ChannelIdx, d.Payload); end
        function onPlotAxisChanged(obj, d), obj.App.onPlotAxisChanged(d.ChannelIdx, d.Payload); end
        function onPlotManagerToggled(obj, d), obj.App.togglePlotManager(d.ChannelIdx); end
        function onPlotDetailsToggled(obj, d), obj.App.togglePlotDetails(d.ChannelIdx); end

        function delete(obj)
            for k = 1:numel(obj.Listeners)
                try
                    if isvalid(obj.Listeners{k}), delete(obj.Listeners{k}); end
                catch
                end
            end
            obj.Listeners = {};
        end
    end
end
% --- End of root/+flightdash/+controller/PlotController.m ---

% --- Start of root/+flightdash/+controller/RoiController.m ---
classdef RoiController < handle
    % flightdash.controller.RoiController
    % Owns ROI events, ROI table state updates, and ROI statistics commands.

    properties (Access = private)
        App
        Listeners cell = {}
    end

    methods
        function obj = RoiController(app)
            obj.App = app;
            obj.subscribeEvents();
        end

        function subscribeEvents(obj)
            EB = @flightdash.util.EventBus.subscribe;
            obj.Listeners{end+1} = EB('RoiAddRequested', @(~,d) obj.addCurrentRoi(d.ChannelIdx));
            obj.Listeners{end+1} = EB('RoiSelectionChanged', @(~,d) obj.onSelectionChanged(d.ChannelIdx, d.Payload));
            obj.Listeners{end+1} = EB('RoiDeleteSelectedRequested', @(~,d) obj.deleteSelectedRoi(d.ChannelIdx));
            obj.Listeners{end+1} = EB('RoiClearRequested', @(~,d) obj.clearRois(d.ChannelIdx));
            obj.Listeners{end+1} = EB('AnalysisComputeRequested', @(~,d) obj.computeAnalysis(d.ChannelIdx));
        end

        function addCurrentRoi(obj, fIdx)
            app = obj.App;
            try
                if isempty(app.Models(fIdx).rawData), return; end
                timeCol = app.Models(fIdx).mappedCols.Time;
                times = app.Models(fIdx).rawData.(timeCol);
                xlims = app.currentPlotXLim(fIdx, times);
                tabIdx = app.currentPlotTabIndex(fIdx);
                plotIdx = app.selectedPlotIndex(fIdx);
                signalName = 'time';
                if ~isempty(tabIdx) && plotIdx > 0 && plotIdx <= numel(app.UI(fIdx).plotMeta{tabIdx})
                    signalName = app.UI(fIdx).plotMeta{tabIdx}{plotIdx}.YColumn;
                end
                row = {xlims(1), xlims(2), signalName, '--', '--'};
                if ~isfield(app.UI(fIdx), 'roiRows') || isempty(app.UI(fIdx).roiRows)
                    app.UI(fIdx).roiRows = row;
                else
                    app.UI(fIdx).roiRows(end+1, :) = row;
                end
                app.UI(fIdx).selectedRoiIdx = size(app.UI(fIdx).roiRows, 1);
                obj.refreshTable(fIdx);
                obj.drawBands(fIdx);
                app.openRoiFigure(fIdx);
            catch ME
                app.logCaught(ME, 'ROI:add');
            end
        end

        function onSelectionChanged(obj, fIdx, event)
            app = obj.App;
            try
                app.UI(fIdx).selectedRoiIdx = 0;
                if isempty(event) || isempty(event.Indices), return; end
                row = event.Indices(1, 1);
                if row >= 1 && isfield(app.UI(fIdx), 'roiRows') && row <= size(app.UI(fIdx).roiRows, 1)
                    app.UI(fIdx).selectedRoiIdx = row;
                end
            catch ME
                app.logCaught(ME, 'ROI:select');
            end
        end

        function deleteSelectedRoi(obj, fIdx)
            app = obj.App;
            try
                if ~isfield(app.UI(fIdx), 'roiRows') || isempty(app.UI(fIdx).roiRows), return; end
                row = 0;
                if isfield(app.UI(fIdx), 'selectedRoiIdx'), row = app.UI(fIdx).selectedRoiIdx; end
                if isempty(row) || row < 1 || row > size(app.UI(fIdx).roiRows, 1), return; end
                app.UI(fIdx).roiRows(row, :) = [];
                app.UI(fIdx).selectedRoiIdx = min(row, size(app.UI(fIdx).roiRows, 1));
                obj.refreshTable(fIdx);
                obj.drawBands(fIdx);
                app.refreshRoiFigure(fIdx);
            catch ME
                app.logCaught(ME, 'ROI:deleteSelected');
            end
        end

        function clearRois(obj, fIdx)
            app = obj.App;
            try
                obj.deleteGraphics(fIdx);
                app.UI(fIdx).roiRows = cell(0, 5);
                app.UI(fIdx).selectedRoiIdx = 0;
                obj.refreshTable(fIdx);
                app.refreshRoiFigure(fIdx);
            catch ME
                app.logCaught(ME, 'ROI:clear');
            end
        end

        function refreshTable(obj, fIdx)
            app = obj.App;
            try
                if isfield(app.UI(fIdx), 'roiTable') && ~isempty(app.UI(fIdx).roiTable) && isvalid(app.UI(fIdx).roiTable)
                    app.UI(fIdx).roiTable.Data = app.UI(fIdx).roiRows;
                end
                app.refreshRoiFigure(fIdx);
            catch ME
                app.logCaught(ME, 'ROI:refreshTable');
            end
        end

        function computeAnalysis(obj, fIdx)
            app = obj.App;
            try
                if ~isfield(app.UI(fIdx), 'roiRows') || isempty(app.UI(fIdx).roiRows)
                    app.openStatsFigure(fIdx);
                    return;
                end
                timeCol = app.Models(fIdx).mappedCols.Time;
                times = app.Models(fIdx).rawData.(timeCol);
                rows = app.UI(fIdx).roiRows;
                for r = 1:size(rows, 1)
                    signalName = rows{r, 3};
                    if ~ismember(signalName, app.Models(fIdx).rawData.Properties.VariableNames)
                        rows{r, 4} = '--';
                        rows{r, 5} = '--';
                        continue;
                    end
                    idx = times >= rows{r, 1} & times <= rows{r, 2};
                    y = app.Models(fIdx).rawData.(signalName);
                    if ~any(idx)
                        rows{r, 4} = '--';
                        rows{r, 5} = '--';
                        continue;
                    end
                    rows{r, 4} = sprintf('%.5g', mean(y(idx), 'omitnan'));
                    targetCol = obj.matchTargetColumn(fIdx, signalName);
                    if ~isempty(targetCol)
                        target = app.Models(fIdx).rawData.(targetCol);
                        err = y(idx) - target(idx);
                        rows{r, 5} = sprintf('RMSE %.5g', sqrt(mean(err.^2, 'omitnan')));
                    else
                        rows{r, 5} = sprintf('STD %.5g', std(y(idx), 'omitnan'));
                    end
                end
                app.UI(fIdx).roiRows = rows;
                obj.refreshTable(fIdx);
                obj.drawBands(fIdx);
                app.openStatsFigure(fIdx);
            catch ME
                app.logCaught(ME, 'ROI:analysis');
            end
        end

        function targetCol = matchTargetColumn(obj, fIdx, signalName)
            app = obj.App;
            targetCol = '';
            vars = app.Models(fIdx).rawData.Properties.VariableNames;
            candidates = {[signalName 'Target'], [signalName '_Target']};
            switch char(signalName)
                case {'Roll', 'roll'}
                    candidates{end+1} = 'RollTarget';
                case {'Pitch', 'pitch'}
                    candidates{end+1} = 'PitchTarget';
                case {'Yaw', 'Heading', 'hdg_deg'}
                    candidates{end+1} = 'YawTarget';
            end
            for k = 1:numel(candidates)
                if ismember(candidates{k}, vars)
                    targetCol = candidates{k};
                    return;
                end
            end
        end

        function drawBands(obj, fIdx)
            app = obj.App;
            try
                obj.deleteGraphics(fIdx);
                if ~isfield(app.UI(fIdx), 'roiRows') || isempty(app.UI(fIdx).roiRows), return; end
                tabIdx = app.currentPlotTabIndex(fIdx);
                if isempty(tabIdx) || isempty(app.UI(fIdx).plotAxes{tabIdx}), return; end
                roiHandles = {};
                for aIdx = 1:numel(app.UI(fIdx).plotAxes{tabIdx})
                    ax = app.UI(fIdx).plotAxes{tabIdx}{aIdx};
                    if isempty(ax) || ~isvalid(ax), continue; end
                    yl = ax.YLim;
                    hold(ax, 'on');
                    for r = 1:size(app.UI(fIdx).roiRows, 1)
                        x0 = app.UI(fIdx).roiRows{r, 1};
                        x1 = app.UI(fIdx).roiRows{r, 2};
                        h = patch(ax, [x0 x1 x1 x0], [yl(1) yl(1) yl(2) yl(2)], ...
                            [0.96 0.74 0.18], 'FaceAlpha', 0.10, 'EdgeColor', 'none', 'HitTest', 'off');
                        app.excludeFromLegend(h);
                        try, uistack(h, 'bottom'); catch, end
                        roiHandles{end+1} = h; %#ok<AGROW>
                    end
                end
                app.UI(fIdx).roiGraphics = roiHandles;
            catch ME
                app.logCaught(ME, 'ROI:draw');
            end
        end

        function deleteGraphics(obj, fIdx)
            app = obj.App;
            try
                if isfield(app.UI(fIdx), 'roiGraphics')
                    app.deleteGraphicsHandles(app.UI(fIdx).roiGraphics);
                end
                app.UI(fIdx).roiGraphics = {};
            catch ME
                app.logCaught(ME, 'ROI:deleteGraphics');
            end
        end

        function delete(obj)
            for k = 1:numel(obj.Listeners)
                try
                    if isvalid(obj.Listeners{k}), delete(obj.Listeners{k}); end
                catch
                end
            end
            obj.Listeners = {};
        end
    end
end
% --- End of root/+flightdash/+controller/RoiController.m ---
